        PRESS_IT_AND_THE_MOG_HOUSE_MENU_WILL                                    = 6798,  -- Press it and the Mog House menu will appear! Everything you can do in your Mog House is there, kupo!
        THERE_ARE_LOTS_OF_THINGS_YOU_CAN_DO                                     = 6799,  -- There are lots of things you can do in your Mog House, kupo! It can be too much for some masters, kupo...
        SO_I_LL_TEACH_YOU_ABOUT_EACH_ONE                                        = 6800,  -- So I'll teach you about each one of them! Ask me what you want to know about, kupo!
        CHOOSE_THE_MOG_HOUSE_COMMAND_YOU_WANT_TO                                = 6801,  -- Choose the Mog House command you want to know about, kupo!
        WHAT_DO_YOU_WANT_TO_KNOW_ABOUT_THE                                      = 6802,  -- What do you want to know about? The Mog Safe. Storage. The Delivery Box. Changing jobs. Gardening. Changing the layout. Mog House invitations. I got it, thanks, kupo!
        THE_MOG_SAFE_IS_WHERE_I_KEEP_ITEMS                                      = 6803,  -- The Mog Safe is where I keep items that you can't carry! It's an especially secure and solid safe, kupo!
        YOU_CAN_ONLY_PUT_SO_MANY_ITEMS_IN                                       = 6804,  -- You can only put so many items in it, kupo... But I'll guard them even if it means my life, kupo!
        THE_DELIVERY_BOX_IS_WHERE_YOU_CAN_SEND                                  = 6805,  -- The Delivery Box is where you can send letters to friends and receive items from various places, kupo!
        YOU_SHOULD_TAKE_THE_ITEMS_FROM_YOUR_DELIVERY                            = 6806,  -- You should take the items from your Delivery Box and put them in your inventory when they arrive, kupo!
        IF_YOUR_DELIVERY_BOX_IS_FULL_NO_MORE                                    = 6807,  -- If your Delivery Box is full, no more deliveries can be made, and you can't send any mail either, kupo!
        YOU_CAN_SEND_ITEMS_AND_GIL_TO_YOUR                                      = 6808,  -- You can send items and gil to your friends with the Send command, kupo!
        SOMETIMES_IF_A_SPECIAL_FORCE_TAKES_HOLD_YOU                             = 6809,  -- (Sometimes, if a special force takes hold, you can even deliver items with the "Exclusive" attribute, kupo...!)
        CHANGING_PEOPLE_S_JOBS_IS_A_SECRET_ABILITY                              = 6810,  -- Changing people's jobs is a secret ability only we moogles can use, kupo!
        I_TAKE_OFF_ALL_YOUR_EQUIPMENT_AND_TAKE                                  = 6811,  -- I take off all your equipment and take you to a mysterious place, kupo!
        AND_THE_REST_IS_A_SECRET_KUPO                                           = 6812,  -- And...the rest is a secret, kupo!
        ALL_MOOGLES_LIKE_TAKING_CARE_OF_PLANTS_KUPO                             = 6813,  -- All moogles like taking care of plants, kupo!
        AS_LONG_AS_YOU_HAVE_A_FLOWERPOT_AND                                     = 6814,  -- As long as you have a flowerpot and seeds, I'll make it my personal responsibility to look after the plants you raise, kupo!
        THIS_MOG_HOUSE_IS_YOUR_VERY_OWN_ROOM                                    = 6815,  -- This Mog House is your very own room, kupo! But it's still a little bare, kupo...
        IT_NEEDS_SOME_FURNITURE_AND_MAYBE_SOME_PAINTINGS                        = 6816,  -- It needs some furniture and maybe some paintings to make it more cozy, kupo!
        IF_YOU_FIND_ANY_DURING_YOUR_TRAVELS_I                                   = 6817,  -- If you find any during your travels, I'll help you lay them out, kupo! I can't wait, kupo!
        STORAGE_SPACE_BECOMES_AVAILABLE_WHEN_YOU_PLACE_FURNITURE                = 6818,  -- Storage space becomes available when you place furniture in your Mog House using the Layout command, kupo!
        IT_S_ALMOST_EXACTLY_THE_SAME_AS_USING                                   = 6819,  -- It's almost exactly the same as using your Mog Safe, kupo! Leave your items here for me to look after, kupo!
        YOU_CAN_INVITE_PARTY_AND_ALLIANCE_MEMBERS_INTO                          = 6820,  -- You can invite party and alliance members into your Mog House, kupo!
        YOU_CAN_SHOW_OFF_YOUR_EXPENSIVE_FURNITURE_HAVE                          = 6821,  -- You can show off your expensive furniture, have tea parties, plan your next great adventure--the possibilities are endless, kupo!
        ARE_YOU_SURE_KUPO_YOU_KNOW_EVERYTHING_ABOUT                             = 6822,  -- Are you sure, kupo? You know everything about your Mog House, kupo?
        ARE_YOU_SURE_I_M_SURE_MAYBE_I                                           = 6823,  -- Are you sure? I'm sure! Maybe I'm not so sure...
