        IF_YOU_TYPE_AE_HELLO_THEN_YOUR_MESSAGE                                  = 6826,  -- If you type /ae Hello!, then your message will be heard by many people.
        IF_YOU_TYPE_AE_FOLLOWED_BY_YOUR_ISSUE                                   = 6827,  -- If you type /ae followed by your issue or question, other adventurers will help you!
        REMEMBER_THAT_YOU_CAN_ONLY_DO_THIS_WHILE                                = 6828,  -- Remember that you can only do this while in town, kupo!
        OKAY_KUPO_GOOD_LUCK_ON_YOUR_ADVENTURING_KUPO                            = 6829,  -- Okay, kupo! Good luck on your adventuring, kupo!
        DO_YOU_WANT_ME_TO_TEACH_YOU_ABOUT                                       = 6830,  -- Do you want me to teach you about your Mog House again, kupo?
        ASK_ABOUT_YOUR_MOG_HOUSE_AGAIN_DON_T                                    = 6831,  -- Ask about your Mog House again? Don't ask. Ask.
        OVER_THE_MOUNTAINS_AND_THE_ROLLING_HILLS_I                              = 6832,  -- Over the mountains and the rolling hills, I'll go wherever my master wills.t
        MASTER_I_TRAVELED_ALL_THE_WAY_HERE_AT                                   = 6833,  -- Master! I traveled all the way here at your bidding, kupo! Even a Rent-a-Room needs a moogle, kupo!
