        WHEN_YOU_GO_BACK_HOME_TALK_TO_THE                                       = 6835,  -- When you go back home, talk to the guard in front of the residential area to call me back to the Mog House, kupo!
        MASTER_I_HAVE_SOMETHING_TO_TELL_YOU_KUPO                                = 6836,  -- Master! I have something to tell you, kupo!
