        OH_MASTER_YOU_WON_T_BELIEVE_WHAT_I                                      = 6855,  -- Oh, Master! You won't believe what I found out on the doorstep this morning, kupo!
        AT_ONCE_SO_GLORIOUS_AND_SO_GHASTLY_AND                                  = 6856,  -- At once so glorious and so ghastly, and just for you! Think of it as a holiday gift from a humble moogle to his favorite (and only) master, kupo!
        FOR_YOUR_OWN_SAFETY_IT_IS_RECOMMENDED_YOU                               = 6857,  -- For your own safety, it is recommended you set the Mog House exit as your home point after changing jobs.
        IS_MY_ASSISTANCE_REACHING_YOU_MASTER_YOUR_MOG                           = 6858,  -- Is my assistance reaching you, Master? Your Mog House is currently aglow with [overwhelming/powerful/faint] [fire/ice/wind/earth/lightning/water/light/dark] energy, kupo!
        IS_MY_ASSISTANCE_REACHING_YOU_MASTER_YOUR_MOG_2                         = 6859,  -- Is my assistance reaching you, Master? Your Mog House is currently aglow with [the overwhelming/the powerful/the faint] energy of many different elements, kupo!
        EACH_ITEM_OF_FURNITURE_YOU_PLACE_USING_THE                              = 6860,  -- Each item of furniture you place using the Layout command corresponds to a different element, kupo! The type of energy that envelops your Mog House changes depending on those elements, kupo!
        WHEN_THAT_ENERGY_CHANGES_MY_POWERS_CHANGE_AS                            = 6861,  -- When that energy changes, my powers change as well, kupo! Master, you should try placing all sorts of furniture in your Mog House, kupo!
