        IF_YOU_HAVEN_T_ALREADY_DONE_SO_YOU                                      = 6878,  -- If you haven't already done so, you should go and speak with a woman named Alaune. She's at the Westgate in Southern San d'Oria, kupo.
        IF_YOU_HAVEN_T_ALREADY_DONE_SO_YOU_2                                    = 6879,  -- If you haven't already done so, you should go and speak with a man named Gulldago. He's at the West Gate in Bastok Markets, kupo.
        IF_YOU_HAVEN_T_ALREADY_DONE_SO_YOU_3                                    = 6880,  -- If you haven't already done so, you should go and speak with a woman named Selele. She's at Leviathan's Gate in Windurst Woods, kupo.
        MASTER_WHAT_YOU_HAVE_THERE_NOW_IF_YOU                                   = 6881,  -- Master! What [an egg-ceptional specimen/egg-ceptional specimens] you have there! Now, if you'll just let me have a look-see, kupo...
