        VOILA_ISN_T_SHE_A_BEAUTY_KUPO_UTTERLY                                   = 6884,  -- Voila! Isn't she a beauty, kupo? Utterly egg-squisite workmanship, I do degg-clare!
        WE_EGG_STRACT_THIS_DOODAD_FROM_THAT_DOOHICKEY                           = 6885,  -- We egg-stract this doodad from that doohickey, just like so, kupo...
