        WHAT_A_TERRIBLY_TROUBLING_TURN_OF_EVENTS_KUPO                           = 6895,  -- What a terribly troubling turn of events, kupo! But have no fear! Sit tight and you'll see why I'm the most renowned handymoogle in the three nations!
        GODDESS_HAVE_MERCY_ON_MY_MOOGLE_SOUL_LOOK                               = 6896,  -- Goddess have mercy on my moogle soul. Look at this mess! Rotting roof boards! Rusted nails, kupo!
        WHY_IT_S_A_MIRACLE_THIS_TOTTERING_TUMBLE                                = 6897,  -- Why, it's a miracle this tottering, tumble-down shanty--I mean, this beautiful abode of yours--is still standing, master!
        ANYHOW_THIS_SIMPLY_WON_T_DO_KUPO_WE                                     = 6898,  -- Anyhow, this simply won't do, kupo. We must make repairs before we have water up to my little wings!
        I_FIGURE_ALL_I_LL_NEED_IS_A                                             = 6899,  -- I figure all I'll need is a good %, %, and % to have this fixed up good as new, kupo!
