        WHICH_REMINDS_ME_I_WENT_AHEAD_AND_RELAYED                               = 6905,  -- Which reminds me, I went ahead and relayed the requisite reports to my manager at the MHMU.
        BUT_WOULDN_T_YOU_KNOW_IT_KUPO_IT                                        = 6906,  -- But wouldn't you know it, kupo? It seems there's been a trifling bit of trouble at one of our Rent-a-Rooms in Jeuno as well!
