        FURTHERMORE_YOU_MAY_TRADE_A_MOOGLE_STORAGE_SLIP                         = 6913,  -- Furthermore, you may trade a moogle storage slip to me to wipe it clean, or mystically entrust its entire contents to me. Quite convenient, wouldn't you say?
        ADJUST_PARAMETERS_EDIT_MAIN_JOB_LEVEL_RESET_ABILITY                     = 6914,  -- Adjust parameters? Edit main job level. Reset ability recast timer. Obtain merit points. Receive all spells/rolls/attachments. Unlock all jobs and support jobs. Cancel.
