        YOU_MAY_USE_ONE_OF_THE_INSTRUMENTS_IN                                   = 6944,  -- You may use one of the instruments in your Mog House to play a different tune.
        PLAY_MUSIC_FROM_WHICH_INSTRUMENT                                        = 6945,  -- Play music from which instrument?
        SELECT_AN_INSTRUMENT_NONE_FOR_NOW                                       = 6946,  -- Select an instrument. None for now. %. %. %. %.
        CHANGE_TO_WHAT_SONG_DON_T_CHANGE_AT                                     = 6947,  -- Change to what song? Don't change at all. Track: [???/Mog House/Awakening/Echoes of a Zephyr/Bustle of the Capital]. Track: [???/Vana'diel March/Belief/The Cosmic Wheel/Jeweled Boughs]. Track: [???/The Kingdom of San d'Oria/A Realm of Emptiness/The Destiny Destroyers/Bandits' Market]. Track: [???/Chateau d'Oraguille/Distant Worlds/Hume Male/Illusions in the Mist]. Track: [???/Ronfaure/Forever Today/Hume Female/Fighters of the Crystal]. Track: [???/The Republic of Bastok/Rhapsodies of Vana'diel/Elvaan Male/Selbina]. Track: [???/Metalworks/Awakening (FFRK Ver.)/Elvaan Female/Mhaura]. Track: [???/Gustaberg/Full Speed Ahead!/Tarutaru Male/#56]. Track: [???/The Federation of Windurst/The Celestial Capital - Al'Taieu/Tarutaru Female/#57]. Track: [???/Heavens Tower/The Grand Duchy of Jeuno/Mithra/#58]. Track: [???/Sarutabaruta/Ru'Lude Gardens/Galka/#59]. Track: [???/The Sacred City of Adoulin/Devils' Delight/Jeuno - Starlight Celebration -/#60]. Track: [???/The Pioneers/Griffons Never Die/Dash de Chocobo/#61]. Track: [???/Kazham/Thunder of the March/Circuit de Chocobo/#62]. Track: [???/The Sanctuary of Zi'Tah/Stargazing/Run Chocobo Run!/#63]. Track: [???/Tu'Lia/Autumn Footfalls/Choc-a-bye Baby/#64]. Previous page. Next page.
        CHANGE_MUSIC_NOT_NOW_TRACK_SELBINA_TRACK_FIGHTERS                       = 6948,  -- Change music? Not now. Track: Selbina. Track: Fighters of the Crystal. Track: A New Horizon. Track: Ragnarok. Track: Clash of Standards. Track: Echoes of Creation. Track: Luck of the Mog. Track: Feast of the Ladies. Track: Abyssea. Track: Melodies Errant. Track: Ronfaure. Track: Autumn Footfalls. Track: Main Theme. Track: Mog House.
        CHANGE_MUSIC_NOT_NOW_MOG_HOUSE_DISTANT_WORLDS                           = 6949,  -- Change music? Not now. Mog House. Distant Worlds.
        CHANGE_MUSIC_NOT_NOW_MOG_HOUSE_THE_PIONEERS                             = 6950,  -- Change music? Not now. Mog House. The Pioneers.
        SELECT_THIS_SONG_YES_THIS_SOUNDS_SPLENDID_NO                            = 6951,  -- Select this song? Yes, this sounds splendid! No, I've changed my tune.
        THIS_SONG_CANNOT_YET_BE_PLAYED                                          = 6952,  -- This song cannot yet be played.
        HANG_ON_I_HAVE_AN_AMAZING_ANNOUNCEMENT                                  = 6953,  -- Hang on! I have an amazing announcement!
        THE_HALLOWED_HALLS_OF_YOUR_HOUSE_ARE_EVEN                               = 6954,  -- The hallowed halls of your house are even more exciting! Why? Because now there's a second floor, kupo!
        BUT_BEFORE_YOU_BASH_YOUR_WAY_IN_I                                       = 6955,  -- But before you bash your way in, I've got a trifling task for you to tackle.
        CAPRICIOUS_MITHRA_CUBS_HAVE_CAJOLED_CRITICAL_INFORMATION_OUT            = 6956,  -- Capricious Mithra cubs have cajoled critical information out of the M.H.M.U., and I want you to wrest it from them!
        VISIT_THE_THREE_NATIONS_AND_QUESTION_THEM_KUPO                          = 6957,  -- Visit the three nations and question them, kupo!
        NOW_YOU_KNOW_THE_NITTY_GRITTY_SO_ENJOY                                  = 6958,  -- Now you know the nitty-gritty, so enjoy your new floor, kupo!
        KUPOPO_YOU_MEAN_YOU_ALREADY_KNOW                                        = 6959,  -- Kupopo? You mean you already know?
        MAGNIFICENT_AND_MARVELOUS_THEN_PROCEED_WITHOUT_DELAY                    = 6960,  -- Magnificent and marvelous! Then proceed without delay!
        ENJOY_EXTRA_SPACE_TO_STORE_YOUR_SUNDRIES                                = 6961,  -- Enjoy extra space to store your sundries!
        REMODEL_YOUR_ROOM_TO_FIT_YOUR_FINICKY_TASTES                            = 6962,  -- Remodel your room to fit your finicky tastes!
        INCORPORATE_OSTENTATIOUS_OVERSEAS_OBJECTS_ALL_THIS_AND_MORE             = 6963,  -- Incorporate ostentatious overseas objects! All this and more!
        BUT_ONLY_ON_THE_SECOND_FLOOR_KUPO_I                                     = 6964,  -- But only on the second floor, kupo. I like the first floor as it is.
        AND_AS_FOR_YOUR_POTTED_PLANTS_THEY_ONLY                                 = 6965,  -- And as for your potted plants--they only persevere on the ground, kupo.
        AND_MOGHANCEMENT_EFFECTS_ONLY_ACTIVATE_FOR_FURNISHINGS_FITTED           = 6966,  -- And moghancement effects only activate for furnishings fitted to the first floor.
        WISH_WE_COULD_HELP_MORE_BUT_WE_SPEND                                    = 6967,  -- Wish we could help more, but we spend enormous amounts of energy on one floor already!
        GO_FORTH_AND_FROLIC_IN_YOUR_NEW_ABODE                                   = 6968,  -- Go forth and frolic in your new abode, kupo!
        YOU_CAN_ACCESS_THE_ANTECHAMBERS_FROM_THE_FRONT                          = 6969,  -- You can access the antechambers from the front door. Enjoy!
        MIGHT_BRING_A_CERTAIN_JE_NE_SAIS_QUOI                                   = 6970,  -- % might bring a certain je ne sais quoi to your Mog House, kupo!
        AH_I_NEVER_THOUGHT_THAT_THIS_DAY_WOULD                                  = 6971,  -- Ah, I never thought that this day would come, kupo...
        INDEED_IT_SEEMS_LIKE_JUST_YESTERDAY_THAT_WE                             = 6972,  -- Indeed, it seems like just yesterday that we first met here.
        I_HAVE_WATCHED_WITH_WONDER_AS_YOU_GREW                                  = 6973,  -- I have watched with wonder as you grew before my very eyes, kupo.
        IN_FACT_I_HEARD_MANY_TALES_OF_YOUR                                      = 6974,  -- In fact, I heard many tales of your boundless bravery from my friends across the world.
        EVERY_TIME_IT_MADE_ME_FEEL_MUCH_LIKE                                    = 6975,  -- Every time, it made me feel much like a proud parent would.
        IT_WAS_LIKE_I_WAS_RIGHT_THERE_WITH                                      = 6976,  -- It was like I was right there with you, kupo.
        THAT_IS_WHY_I_CEASELESSLY_CLEANED_YOUR_MOG                              = 6977,  -- That is why I ceaselessly cleaned your Mog House, merrily managed your belongings, and watered your plants.
        I_COULDN_T_REALLY_THINK_OF_ANY_OTHER                                    = 6978,  -- I couldn't really think of any other ways to help you, kupo.
        HOWEVER_I_HEARD_ABOUT_THE_TRIALS_AND_TRIBULATIONS                       = 6979,  -- However, I heard about the trials and tribulations that you've been through.
        VALHALLA_THE_MAELSTROM_MAGE_CHAOS                                       = 6980,  -- Valhalla, the Maelstrom Mage, Chaos...
        KUPOPOPO_NOW_I_CAN_ACTUALLY_ASSIST_YOU                                  = 6981,  -- Kupopopo! Now I can actually assist you!
        IT_IS_TIME_FOR_US_TO_JOYFULLY_JOIN                                      = 6982,  -- It is time for us to joyfully join forces, kupo!
        WE_CAN_DISCUSS_DETAILS_AT_THE_STONE_CIRCLE                              = 6983,  -- We can discuss details at the stone circle in the La Theine Plateau! I'll be waiting for you there, kupo!
        YOU_GO_ON_AHEAD_AND_WE_LL_SEE                                           = 6984,  -- You go on ahead, and we'll see each other soon!
        I_AM_CHARGED_WITH_THE_TASK_OF_ASSISTING                                 = 6985,  -- I am charged with the task of assisting novice adventurers. What would you like to know?
        WHAT_WOULD_YOU_LIKE_TO_KNOW_HOW_DO                                      = 6986,  -- What would you like to know? How do I give items to people? Where can I fight monsters? What are quests and missions? I want to see a map of the city. Nothing for now.
        GIVING_ITEMS_TO_OTHER_PEOPLE_IS_CALLED_TRADING                          = 6987,  -- Giving items to other people is called trading. It is done by selecting Trade from the main menu on the right.
        YOU_MUST_TARGET_THE_PERSON_EITHER_BEFORE_OR                             = 6988,  -- You must target the person either before or after selecting Trade. Then just choose the items you wish to give the person when your inventory window appears.
        TRADING_IS_CRUCIAL_TO_COMPLETING_QUESTS_AND_MISSIONS                    = 6989,  -- Trading is crucial to completing quests and missions, and also during conquests. Remember it well.
        IF_YOU_HAVE_IN_YOUR_POSSESSION_USE_TRADE                                = 6990,  -- If you have % in your possession, use Trade now to give it to me. I will hand you some starting gil in return.
        BEFORE_YOU_TAKE_ON_ANY_FIENDS_THERE_ARE                                 = 6991,  -- Before you take on any fiends, there are a few things you should remember. First, always have weapons and armor equipped, and spells memorized from scrolls.
        SECOND_ALWAYS_CHECK_YOUR_TARGET_BEFORE_ENGAGING_IT                      = 6992,  -- Second, always check your target before engaging it. Never take on a foe that seems too strong for you to defeat alone.
        THIRD_WHEN_YOU_ARE_IN_A_PARTY_MAKE                                      = 6993,  -- Third, when you are in a party, make it a habit to cast lots for your share of the party spoils after successfully defeating a monster.
        SOME_PEOPLE_IN_TOWN_WILL_ASK_YOU_TO                                     = 6994,  -- Some people in town will ask you to do certain tasks for them. These are called quests. Complete them, and they should reward you for your efforts.
        THERE_ARE_ALSO_TASKS_YOU_CAN_DO_FOR                                     = 6995,  -- There are also tasks you can do for your country, known as missions. There is a guard at each gate charged with assigning them. Speak to the guards for more details.
        COME_TO_ME_IF_THERE_IS_ANYTHING_MORE                                    = 6996,  -- Come to me if there is anything more you would like to know.
        GOOD_HERE_IS_YOUR_STARTING_GIL                                          = 6997,  -- %, good. Here is your starting gil.
        HERE_IS_A_MAP_OF_THE_ENTIRE_CITY                                        = 6998,  -- Here is a map of the entire city. You are currently in [the Mines District/the Markets District/Port Bastok/the Metalworks].
        USE_THE_MAP_IN_THE_MAIN_MENU_FOR                                        = 6999,  -- Use the Map in the main menu for a more detailed view of your surroundings.
        YOU_WOULD_DO_WELL_TO_SPEAK_WITH_A                                       = 7000,  -- You would do well to speak with a man named Gulldago. You can find him by the West Gate in Bastok Markets.
        INQUIRE_ABOUT_WHAT_I_WANT_TO_FIND_SOME                                  = 7001,  -- Inquire about what? I want to find some quests! I want to try the tutorial event! Teach me about Records of Eminence! Teach me about the Trust initiative! I want a map of my current area! I want maps of Bastok! How do I give items to people? How do I fight outside town? What are quests and missions? I have other questions. Nothing for now.
        I_CAN_BESTOW_SOME_MAGICAL_MARKINGS_ON_YOUR                              = 7002,  -- I can bestow some magical markings on your map of the Bastok area if you want to know some helpful spots.
        THERE_ARE_VENDORS_THAT_SELL_MAPS_IN_BOTH                                = 7003,  -- There are vendors that sell maps in both Bastok Markets and Port Bastok, but the former is closer.
        THE_MAP_VENDOR_S_IN_ONE_OF_THE                                          = 7004,  -- The map vendor's in one of the tents up that stairway to the north.
        IF_YOU_RE_LOOKING_FOR_SOMEONE_SELLING_MAPS                              = 7005,  -- If you're looking for someone selling maps, head down those stairs to the south and keep going until you reach an open area. The vendor's tent should be there.
        WE_VE_PREPARED_A_VARIETY_OF_INSTRUCTIONAL_TASKS                         = 7006,  -- We've prepared a variety of instructional tasks for Bastokers new to the whole adventuring thing.
        IF_YOU_RE_INTERESTED_TALK_TO_GULLDAGO_NEAR                              = 7007,  -- If you're interested, talk to Gulldago near the gate to South Gustaberg in Bastok Markets.
        FIRST_HEAD_WEST_OF_HERE_THEN_TURN_NORTH                                 = 7008,  -- First, head west of here, then turn north towards a tunnel. Pass through it and you should arrive at the markets.
        HEAD_WEST_OF_HERE_UNTIL_YOU_CAN_T                                       = 7009,  -- Head west of here until you can't go any further, then turn south and cross over Rye Bridge. That should get you to the markets.
        ONCE_YOU_RE_THERE_GO_FIND_GULLDAGO_I                                    = 7010,  -- Once you're there, go find Gulldago. I'll mark him on your map for you.
        TO_CONFIRM_WHAT_YOU_VE_MARKED_SELECT_MARKERS                            = 7011,  -- To confirm what you've marked, select Markers under Map in the main menu, then press the right arrow key.
        YOU_CAN_ALSO_SELECT_WIDE_SCAN_UNDER_THE                                 = 7012,  -- You can also select Wide Scan under the Map submenu to search for people in your vicinity.
        WHETHER_YOU_RE_NEW_TO_VANA_DIEL_OR                                      = 7013,  -- Whether you're new to Vana'diel or a veteran chomping at the bit, Records of Eminence is a great way to easily participate in a variety of content and earn dazzling rewards.
        OPEN_UP_THE_MAIN_MENU_GO_TO_THE                                         = 7014,  -- Open up the main menu, go to the right, and select Objective List under the Quests submenu.
        FROM_THERE_OPEN_UP_THE_TUTORIAL_MENU_AND                                = 7015,  -- From there, open up the Tutorial menu and select Basics, and get started with First Step Forward.
        I_LL_EVEN_GIVE_YOU_A_LITTLE_HINT                                        = 7016,  -- I'll even give you a little hint for completing First Step Forward.
        GO_FORTH_IN_BASTOK_MARKETS_AND_SPEAK_WITH                               = 7017,  -- Go forth in Bastok Markets and speak with the designated individual. Here, let me place a marker on your map.
        RECORDS_OF_EMINENCE_HAS_A_LITTLE_BIT_OF                                 = 7018,  -- Records of Eminence has a little bit of something for everyone, so be sure to give it a go!
        THE_TRUST_INITIATIVE_CONSISTS_OF_A_NEW_TYPE                             = 7019,  -- The Trust initiative consists of a new type of magic developed by one of Vana'diel's most prestigious magical organizations.
        THOSE_WHO_PASS_THE_INITIATION_RITES_AND_FORM                            = 7020,  -- Those who pass the initiation rites and form special bonds will be rewarded with allies to join them on their journeys.
        YOU_MUST_BE_LEVEL_FIVE_OR_GREATER_TO                                    = 7021,  -- You must be level five or greater to participate in the Trust initiative. I'll be glad to guide you once you are.
        CLARION_STAR_IN_PORT_BASTOK_IS_IN_CHARGE                                = 7022,  -- Clarion Star in Port Bastok is in charge of the Trust initiative here in our fair city. Let me mark his location on your map.
        OPENING_THE_MAIN_MENU_AND_PRESSING_THE_RIGHT                            = 7023,  -- Opening the main menu and pressing the right arrow key will bring you to the second page of the menu, where the Help Desk option is.
        SELECT_THAT_THEN_CLICK_THE_HELP_DESK_OPTION                             = 7024,  -- Select that, then click the Help Desk option again in the menu that pops up. After that, one of the categories will be I need help with the game controls.
        IF_YOU_EVER_HAVE_A_PROBLEM_A_QUICK                                      = 7025,  -- If you ever have a problem, a quick look there might help you figure things out.
        CITIZENS_ALL_OVER_THE_REPUBLIC_NEED_YOUR_HELP                           = 7026,  -- Citizens all over the republic need your help. Do you want to search my records to find some of them?
        INQUIRE_ABOUT_WHICH_LOCALE_NONE_BASTOK_MINES_INDIVIDUAL                 = 7027,  -- Inquire about which locale? None. Bastok Mines: # individual[/s]. Bastok Markets: # individual[/s]. Port Bastok: # individual[/s]. Metalworks: # individual[/s].
        TALK_TO_THE_FOLLOWING_PEOPLE_IN_WHO_SHOULD                              = 7028,  -- Talk to the following people in [the mines/the markets/the port/the Metalworks], who should be more than happy to entrust you with some tasks.
        WHO_WILL_YOU_GO_SEE_IN_BASTOK_MINES                                     = 7029,  -- Who will you go see in Bastok Mines? No one. Wahid. Elki. Tami. Gerbaum. Black Mud. Elki. Pavvke. Detzo. Goraow. Gumbah. Gumbah. Virnage. Titus. Phara. Phara. Deidogg. Gumbah. Selliste.
        WHO_WILL_YOU_GO_SEE_IN_BASTOK_MARKETS                                   = 7030,  -- Who will you go see in Bastok Markets? No one. Malene. Salimah. Michea. Aquillina. Arawn. Nbu Latteh. Foss. Degenhard. Offa. Brygid. Horatius. Michea. Nbu Latteh. Marin. Gwill. Zon-Fobun. Enu. Brygid. Shamarhaan.
        WHO_WILL_YOU_GO_SEE_IN_PORT_BASTOK                                      = 7031,  -- Who will you go see in Port Bastok? No one. Powhatan. Corann. Talib. Talib. Alib-Mufalib. Ronan. Valah Molkot. Clarion Star. Gudav. Benita. Evi. Qiji. Yazan. Raifa. Romilda. Agapito. Ensetsu. Kurando. Powhatan. Carmelo. Hilda. Juroro. Trilok. Carmelo. Carmelo. Ferrol. Oggbi. Oggbi. Oggbi. Grin.
        QHT_HILDOLF_WHO_WILL_YOU_GO_SEE_IN                                      = 7032,  -- qht(Hildolf) Who will you go see in the Metalworks? No one. Hungry Wolf. Izabele. Ferghus. Raibaht. Hildolf. Unlucky Rat. Baldric. Mighty Fist. Raibaht. Cid. High Bear. Ayame. Ayame. Raibaht. Ayame. Ayame. Raibaht. Cid. Zeid. Ayame. Iron Eater. Cid.
        LET_ME_MARK_THEIR_POSITION_ON_YOUR_MAP                                  = 7033,  -- Let me mark their position on your map.
        FINALLY_SOME_INFORMATION_TO_HELP_YOU_IN_YOUR                            = 7034,  -- FiNAllY, sOmE InFOrmAtiOn tO hELp yOu In yoUr TrAVelS.
        ONE_MORE_THING                                                          = 7035,  -- One more thing.
        I_HAVE_SAVED_A_RATHER_PARAMOUNT_DETAIL_FOR                              = 7036,  -- I have saved a rather paramount detail for last. Allow me to explain.
        THERE_S_STILL_ONE_OTHER_THING_REMAINING_TO                              = 7037,  -- There's still one other thing remaining to share with you.
        YOU_CAN_WARP_BETWEEN_PLACES_KNOWN_AS_HOME                               = 7038,  -- YoU CAn wArP BetWEen PlACes KnOwn aS HoME pOinTs. TheY ARe moST CoNveNieNT, sO maKe SuRE to ReGIsTer ThEM bY TouCHing ThE SurFaCE.
        HOME_POINTS_WILL_PROBABLY_TURN_OUT_TO_BE                                = 7039,  -- Home points will probably turn out to be among your best companions. Make sure to examine one if you find it, so you can warp between them and cover large distances fast.
        YOU_MAY_TELEPORT_BETWEEN_THESE_CRYSTALLINE_NODES_CALLED                 = 7040,  -- You may teleport between these crystalline nodes called home points for efficient travel. Be sure to examine any you stumble upon.
        THERE_S_SOME_SPECIAL_CRYSTAL_NODES_KNOWN_AS                             = 7041,  -- There's some special crystal nodes known as home points that'll undoubtedly serve you well. Don't forget to interact with all that you find, as they can help you get to far away places.
        IF_YOU_FIND_YOURSELF_IN_A_FARAWAY_PLACE                                 = 7042,  -- If yOU fINd yOurSeLF iN A fARaWay pLaCe, maKe sURe tO FinD a StoRE to BuY a Map fROm! wIth a MaP, yoU CaN ChEck WheRe yOu ArE!
        SHOULD_YOU_FIND_YOURSELF_LOST_IN_THE_MIDDLE                             = 7043,  -- Should you find yourself lost in the middle of nowhere, try to make it back to town to buy a map. That way, you can get your bearings.
        REMEMBER_TO_PURCHASE_A_MAP_FROM_THE_APPROPRIATE                         = 7044,  -- Remember to purchase a map from the appropriate vendor before going to a faraway land. If you do, you can check your location within that place.
        DID_YOU_KNOW_THAT_SOME_VENDORS_WILL_SELL                                = 7045,  -- Did you know that some vendors will sell you maps of specific areas? It sure beats stumbling around like a dullard!
        DON_T_WASTE_PRECIOUS_ITEMS_BY_SELLING_THEM                              = 7046,  -- DoN'T WaSTe pRecIOus iTemS By sEllINg tHeM tO a StoRe. MaKE eVen MoRe MonEy By PuTTing tHeM uP At tHe AucTIon HouSe!
        I_HATE_TO_SAY_IT_BUT_THE_MERCHANTS                                      = 7047,  -- I hate to say it, but the merchants around here are pretty stingy. You'd have more luck listing any unwanted goods at the auction house.
        I_ADVISE_YOU_TO_PUT_ANY_UNWANTED_GOODS                                  = 7048,  -- I advise you to put any unwanted goods up for sale at the auction house rather than be taken advantage of by the vendors here.
        IF_THERE_S_SOMETHING_YOU_VE_GOT_THAT                                    = 7049,  -- If there's something you've got that you don't need, try putting it up at the auction house rather than selling it to some unscrupulous vendor.
        MANY_UNDEAD_MONSTERS_CAN_SENSE_WHEN_YOU_ARE                             = 7050,  -- MaNY uNdEaD MOnsTeRS cAn SenSe WhEn yOU Are LoW oN HP, aNd wIll TAke tHaT opPOrtUnItY tO ComE AfTEr yOu!
        UNDEAD_ENEMIES_TEND_TO_COME_OUT_OF_THE                                  = 7051,  -- Undead enemies tend to come out of the woodwork when your HP is low. Be careful.
        THE_UNDEAD_OFTEN_ASSAULT_ADVENTURERS_WITH_LOW_HP                        = 7052,  -- The undead often assault adventurers with low HP, which is all the more reason to never let your guard down in the wilderness.
        UNDEAD_ARE_ALWAYS_OUT_FOR_BLOOD_AND_BRAINS                              = 7053,  -- Undead are always out for blood and brains, so watch out if you're low on health! They'll make a beeline right for you.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_STRENGTH                    = 7054,  -- LeT'S tALk aBouT AttRIButeS. InCReaSing yoUr StrenGTh (STR) wiLL iNcrEase YouR pHYsiCal, bUt NOt MaGiCal, AttACk.
        INCREASING_YOUR_STRENGTH_STR_RAISES_YOUR_ATTACK_POWER                   = 7055,  -- Increasing your strength (STR) raises your attack power, but--sadly--not your magic attack.
        INCREASING_YOUR_STRENGTH_STR_ENHANCES_YOUR_ATTACK_POWER                 = 7056,  -- Increasing your strength (STR) enhances your attack power, but--regrettably--does nothing for your magic attack.
        INCREASING_YOUR_STRENGTH_STR_ENHANCES_YOUR_ATTACK_POWER_2               = 7057,  -- Increasing your strength (STR) enhances your attack power, but unfortunately does nothing for the efficacy of your magic.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_DEXTERITY                   = 7058,  -- LeT'S tALk aBouT AttRIButeS. InCReaSinG yoUr DeXteRIty (DEX) wiLl IncReaSe yOuR AccURacY aNd cRiTIcaL HIt rAtE.
        INCREASING_YOUR_DEXTERITY_DEX_INCREASES_THINGS_LIKE_YOUR                = 7059,  -- Increasing your dexterity (DEX) increases things like your accuracy and critical hit rate.
        INCREASING_YOUR_DEXTERITY_DEX_IMPROVES_SUCH_FACULTIES_AS                = 7060,  -- Increasing your dexterity (DEX) improves such faculties as accuracy and critical hit rate.
        INCREASING_YOUR_DEXTERITY_DEX_ENHANCES_ATTRIBUTES_SUCH_AS               = 7061,  -- Increasing your dexterity (DEX) enhances attributes such as accuracy and critical hit rate.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_VITALITY                    = 7062,  -- LeT'S tALk aBouT AttRIButeS. InCreAsinG YoUR VitALiTy (VIT) WiLL iNcReaSE yOuR PhYsiCAl DefENsE anD HP reStoREd bY CuRe aNd oTheR HP-HeaLInG aBilItieS.
        INCREASING_YOUR_VITALITY_VIT_INCREASES_THINGS_LIKE_YOUR                 = 7063,  -- Increasing your vitality (VIT) increases things like your physical defense and the potency of restorative abilities such as Cure.
        INCREASING_YOUR_VITALITY_VIT_IMPROVES_SUCH_FACULTIES_AS                 = 7064,  -- Increasing your vitality (VIT) improves such faculties as physical defense and the potency of restorative abilities like Cure.
        INCREASING_YOUR_VITALITY_VIT_ENHANCES_ATTRIBUTES_SUCH_AS                = 7065,  -- Increasing your vitality (VIT) enhances attributes such as physical defense and restorative abilities such as cure.
        LET_S_TALK_ABOUT_ATTRIBUTES_AGILITY_AGI_HAS                             = 7066,  -- LeT'S tALk aBouT AttRIButeS. AgIlITy (AGI) hAs a VarIetY Of EffECtS, sUch aS IncReaSing pHYsIcaL EvaSioN And aCCurAcy oF RangEd aTTacKs, as WelL aS DecReasINg eNEmiES' CRitIcAL HiT EvaSioN.
        INCREASING_YOUR_AGILITY_AGI_INCREASES_THINGS_LIKE_YOUR                  = 7067,  -- Increasing your agility (AGI) increases things like your physical evasion and ranged accuracy. It also decreases enemies' critical hit evasion.
        INCREASING_YOUR_AGILITY_AGI_IMPROVES_SUCH_FACULTIES_AS                  = 7068,  -- Increasing your agility (AGI) improves such faculties as physical evasion and ranged accuracy. It also reduces enemies' critical hit evasion.
        INCREASING_YOUR_AGILITY_AGI_ENHANCES_ATTRIBUTES_SUCH_AS                 = 7069,  -- Increasing your agility (AGI) enhances attributes such as physical evasion and ranged accuracy. It also decreases enemies' critical hit evasion.
        LET_S_TALK_ABOUT_ATTRIBUTES_INTELLIGENCE_INT_INCREASES                  = 7070,  -- LeT'S tALk aBouT AttRIButeS. InTElLiGEncE (INT) iNcReaSEs tHe MagIC aCCuraCy and DaMAge Of ElEmenTAL MaGiC sPeLLs.
        INCREASING_YOUR_INTELLIGENCE_INT_INCREASES_THINGS_LIKE_THE              = 7071,  -- Increasing your intelligence (INT) increases things like the accuracy and damage of your elemental magic spells.
