        HMM_YES_I_AM_PARRAGGOH_AH_CORNELIA_TOLD                                 = 10595,  -- Hmm? Yes, I am Parraggoh. Ah, Cornelia told you of my predicament.
        WELL_THEN_SHE_PUT_HER_TRUST_IN_YOU                                      = 10596,  -- Well, then. She put her trust in you, so I will do the same.
        THANK_YOU_IT_PAINS_ME_TO_HAVE_TO                                        = 10597,  -- Thank you. It pains me to have to rely on people's kindness like this, but you have my gratitude.
        IT_PAINS_ME_TO_HAVE_TO_RELY_ON                                          = 10598,  -- It pains me to have to rely on people's kindness like this, but you have my gratitude.
        I_MUST_THANK_CORNELIA_FOR_HER_KINDNESS_AS                               = 10599,  -- I must thank Cornelia for her kindness as well...
        AH_YOU_HAVE_BROUGHT_ME                                                  = 10600,  -- Ah! You have brought me %!
        HMM_YES_I_AM_PARRAGGOH                                                  = 10601,  -- Hmm? Yes, I am Parraggoh.
        WHAT_CORNELIA_ASKED_YOU_AND_YOU_VE_BROUGHT                              = 10602,  -- What? Cornelia asked you...and you've brought me %?
        THANK_YOU_I_REALLY_NEEDED_THESE                                         = 10603,  -- Thank you! I really needed these!
        IT_MAY_NOT_BE_MUCH_OF_A_REWARD                                          = 10604,  -- It may not be much of a reward, but I want you to have this.
        IF_YOU_SEE_CORNELIA_SEND_HER_MY_GRATITUDE                               = 10605,  -- If you see Cornelia, send her my gratitude.
        NO_WAIT_INSTEAD_TELL_HER_SHE_SHOULD_NOT                                 = 10606,  -- No, wait-- Instead, tell her she should not be seen around us Galka too much.
        FOR_HER_OWN_SAKE                                                        = 10607,  -- For her own sake.
        AH_IT_S_GOOD_TO_SEE_YOU_AGAIN                                           = 10608,  -- Ah! It's good to see you again. How have you been?
        THIS_IS_NO_PLACE_FOR_YOU_TO_BE                                          = 10609,  -- This is no place for you to be wandering around. Get out of my sight, outsider.
        HAVE_YOU_SEEN_GUMBAH_YES_NO                                             = 10610,  -- Have you seen Gumbah? Yes. No.
        OKAY_IF_YOU_SEE_HIM_AGAIN_TELL_HIM                                      = 10611,  -- Okay. If you see him again, tell him not to run away next time!
        WHAT_HE_RAN_AWAY_AGAIN                                                  = 10612,  -- What? He ran away again?
        HE_NEVER_STANDS_HIS_GROUND_BUT_I_LL                                     = 10613,  -- He never stands his ground! But I'll get him next time!
        HEY_YOU_DID_YOU_SEE_A_SMALL_GALKA                                       = 10614,  -- Hey, you! Did you see a small Galka called Gumbah?
        I_M_HERE_WHAT_DO_YOU_WANT                                               = 10615,  -- I'm here. What do you want?
        AH_FINALLY_WE_MEET_AGAIN_PREPARE_TO_FACE                                = 10616,  -- Ah! Finally, we meet again! Prepare to face your doom!
        OH_NOT_AGAIN_DIDN_T_I_BEAT_YOU                                          = 10617,  -- Oh, not again. Didn't I beat you last time? You've always been such a pestering child...
        HEY_YOU_RE_NOT_MUCH_OLDER_THAN_I                                        = 10618,  -- Hey, you're not much older than I am! Don't talk to me like you're some old man!
        AND_YOU_CHEATED_LAST_TIME_YOU_BROUGHT_ONE                               = 10619,  -- And you cheated last time! You brought one of Werei's old swords!
        YOU_DIDN_T_SAY_I_COULDN_T_BESIDES                                       = 10620,  -- You didn't say I couldn't. Besides, you cheated first. I saw you borrow Deidogg's sword.
        URK_WELL_UH_FORGET_SWORDS_THIS_TIME_IT                                  = 10621,  -- Urk... Well, uh...forget swords! This time, it's helms! Whoever brings the best helm wins! And don't bring any of Werei's, Gumbah!
        OH_PLEASE_FINE_I_FORFEIT_YOU_WIN_CAN                                    = 10622,  -- Oh, please... Fine, I forfeit. You win. Can I go now?
        NO_NO_NO_YOU_RE_NOT_RUNNING_AWAY                                        = 10623,  -- No, no, no! You're not running away again!
        ANYWAY_I_M_THINKING_OF_BRINGING_HEY_YOU                                 = 10624,  -- Anyway, I'm thinking of bringing %. Hey, you're an adventurer, right? You have one, don't you?
        CAN_I_BORROW_IT_FOR_JUST_A_FEW                                          = 10625,  -- Can I borrow it for just a few seconds? I'll give it back, promise! I'll even give you a reward!
        OOH_THANKS_NOW_I_LL_SHOW_THAT_GUMBAH                                    = 10626,  -- Ooh! %! Thanks! Now I'll show that Gumbah...
        YOU_RE_BORROWING_AGAIN                                                  = 10627,  -- You're borrowing again...
        THERE_YOU_ARE_HA_HA_LOOK_I_HAVE                                         = 10628,  -- There you are! Ha-ha! Look, I have %! Victory is mine!
        UH_HUH_GOOD_FOR_YOU_MY_HELM_SHOULD                                      = 10629,  -- Uh-huh, good for you. My helm should be here soon.
        THERE_YOU_ARE_HERE_I_BROUGHT_THE_YOU                                    = 10630,  -- There you are! Here, I brought the % you asked for!
        HOW_S_THIS_DO_I_WIN                                                     = 10631,  -- How's this? Do I win?
        HEY_THAT_S_NOT_FAIR_YOU_TRICKED_HER                                     = 10632,  -- Hey! That's not fair! You tricked her into bringing you that helm!
        HUH_TRICKED_WHAT_S_GOING_ON_WHERE_S                                     = 10633,  -- Huh? Tricked? What's going on? Where's the Galka adventurer who needed a helm?
        GUMBAH_WERE_YOU_LYING_TO_ME_EXPLAIN_YOURSELF                            = 10634,  -- Gumbah! Were you lying to me? Explain yourself!
        WELL_UH_I_GOTTA_GO                                                      = 10635,  -- Well, uh... I gotta go!
        HEY_IF_YOU_RUN_I_WIN_HA_WHAT                                            = 10636,  -- Hey! If you run, I win! Ha! What do you say to that!?
        FINE_BY_ME_SEE_YOU                                                      = 10637,  -- Fine by me! See you!
        GUMBAH_COME_BACK_HERE_THIS_INSTANT                                      = 10638,  -- Gumbah! Come back here this instant!
        WHY_DO_I_FEEL_LIKE_I_VE_LOST                                            = 10639,  -- Why do I feel like I've lost? Anyway, thanks. Here's the reward I promised you.
        I_M_HERE_IN_BASTOK_TO_INVESTIGATE_A                                     = 10640,  -- I'm here in Bastok to investigate a few things about the Palborough Mines.
        YOU_RE_AN_ADVENTURER_AREN_T_YOU_COULD                                   = 10641,  -- You're an adventurer, aren't you? Could you do me a favor?
        THERE_IS_A_MONUMENT_AT_THE_TOP_OF                                       = 10642,  -- There is a monument at the top of Zegham Hill in North Gustaberg, erected in honor of the pioneers who dug the Palborough Mines.
        MY_GREAT_GRANDFATHER_WAS_ONE_OF_THEM_I                                  = 10643,  -- My great-grandfather was one of them. I wanted to go visit his grave there, but I couldn't get past all the monsters.
        IF_IT_S_NOT_TOO_MUCH_TROUBLE_I                                          = 10644,  -- If it's not too much trouble, I was wondering if you could place this % at the monument for me.
        VISIT_THE_MONUMENT_IN_ELKI_S_STEAD_YES                                  = 10645,  -- Visit the monument in Elki's stead? Yes. No.
        THANK_YOU_THERE_ARE_TEN_NAMES_ENGRAVED_ON                               = 10646,  -- Thank you. There are ten names engraved on the monument. Look for an Omran. He was my great-grandfather.
        OF_COURSE_I_M_SORRY_ASKING_A_TOTAL                                      = 10647,  -- Of course... I'm sorry. Asking a total stranger to risk his life for me... I was being presumptuous.
        THANK_YOU_FOR_YOUR_KINDNESS_IT_S_GOOD                                   = 10648,  -- Thank you for your kindness. It's good to hear that Omran's name is still there, after all these years.
        THERE_WAS_AN_ELEVENTH_NAME_VIG_T_O                                      = 10649,  -- There was an eleventh name? Vig****t O**? No, I'm sorry, I don't know who that is. Wait, unless...
        NO_NEVER_MIND_THANK_YOU_AGAIN_HERE_THIS                                 = 10650,  -- No, never mind. Thank you again. Here, this is for your trouble.
        AH_IT_S_YOU_THANK_YOU_FOR_THE                                           = 10651,  -- Ah, it's you. Thank you for the other day. As you might have guessed, visiting my great-grandfather's grave was not the only thing I came here to do.
        UPON_FURTHER_EXAMINATION_OF_MY_GREAT_GRANDFATHER_S                      = 10652,  -- Upon further examination of my great-grandfather's diary, I've come to believe that there were eleven pioneers who dug the Palborough Mines, not ten.
        MY_GREAT_GRANDFATHER_SEEMED_TO_TRULY_REGRET_THE                         = 10653,  -- My great-grandfather seemed to truly regret the fact that this last pioneer's name was never recorded in the annals alongside theirs.
        I_BELIEVE_THE_NAME_YOU_FOUND_THIS_VIG                                   = 10654,  -- I believe the name you found, this Vig****t O**, is the name of that last pioneer...
        BUT_I_CAN_T_SEEM_TO_FIND_A                                              = 10655,  -- But I can't seem to find a name to fit those letters. It has been more than a hundred fifty years, so I don't think he'd still be alive, but...
        IF_YOU_CAN_FIND_ANY_INFORMATION_ON_THIS                                 = 10656,  -- If you can find any information on this person, I'd be truly grateful.
        HELP_INVESTIGATE_ASK_FOR_MORE_INFORMATION_HELP_DON                      = 10657,  -- Help investigate? Ask for more information. Help. Don't help.
        THE_PALBOROUGH_MINES_WERE_THE_FIRST_MINES_TO                            = 10658,  -- The Palborough Mines were the first mines to be dug using explosives, a Hume invention.
        BEFORE_THEN_BASTOK_HAD_TO_RELY_ON_THE                                   = 10659,  -- Before then, Bastok had to rely on the strength of the Galka to dig its mines. When the ten Hume pioneers dug one using only their wits and technology, it was a major turning point in Bastok's history.
        ANY_OTHER_CLUE_THAT_MIGHT_SHED_LIGHT_ON                                 = 10660,  -- Any other clue that might shed light on the Palborough Mines' past would be in the mines themselves.
        THANK_YOU_IF_YOU_FIND_ANYTHING_OUT_PLEASE                               = 10661,  -- Thank you. If you find anything out, please tell me right away.
        I_SEE_THANKS_ANYWAY                                                     = 10662,  -- I see... Thanks anyway.
        ELEVEN_SETS_OF_TOOLS_THE_NAMES_OF_THE                                   = 10663,  -- Eleven sets of tools? The names of the pioneers are written on them...
        THE_ELEVENTH_PIONEER_S_NAME_WAS_VIGILANT_OWL                            = 10664,  -- The eleventh pioneer's name was...Vigilant Owl? It sounds like a Galka name.
        AND_THEY_SAY_THE_PALBOROUGH_MINES_WERE_DUG                              = 10665,  -- And they say the Palborough Mines were dug only by Humes...
        WAIT_THERE_S_ANOTHER_INSCRIPTION_ON_THIS_TOOL                           = 10666,  -- Wait, there's another inscription on this tool... Babenn? Is that another name?
        I_WONDER_WHAT_THIS_MEANS_I_LL_TRY                                       = 10667,  -- I wonder what this means... I'll try to find out more on my side, but let me know if you come across any more information.
        AN_ELEVENTH_PALBOROUGH_MINES_PIONEER_THEN_IT_IS                         = 10668,  -- An eleventh Palborough Mines Pioneer? Then it is as I thought!
        YOU_BROUGHT_ME_THE_MORE_I_READ_THEM                                     = 10669,  -- % you brought me--the more I read them, the more I am convinced someone has tampered with them!
        IT_MUST_BE_HUMES_ONLY_THEY_WOULD_GO                                     = 10670,  -- It must be Humes! Only they would go so far as erasing our history to protect their over-swollen pride!
        I_MY_APOLOGIES_I_SHOULD_NOT_LET_MY                                      = 10671,  -- I... My apologies. I should not let my emotions get the better of me.
        THE_PIONEERS_WELL_YES_I_WORKED_IN_THE                                   = 10672,  -- The pioneers? Well, yes, I worked in the mines until fifteen years ago, but you're talking about things that happened more than a hundred and fifty years back!
        I_MAY_BE_OLD_BUT_I_M_NOT                                                = 10673,  -- I may be old, but I'm not that old. Go talk to Babenn. Now that Werei's gone, he's the only Galka left who was around back then.
        THE_PALBOROUGH_PIONEERS_YES_I_WAS_ALIVE_BACK                            = 10674,  -- The Palborough Pioneers? Yes, I was alive back then, but I recall I was away adventuring in those days. I'm afraid I can't help you with what you seek.
        HMM_WHAT_IS_IT_YOU_WANT_WITH_AN                                         = 10675,  -- Hmm? What is it you want with an old Galka like me?
        VIGILANT_OWL_THAT_NAME_DOES_NOT_MEAN_ANYTHING                           = 10676,  -- Vigilant...Owl? That name does not mean anything to me.
        I_HAVE_NOTHING_TO_TELL_YOU_GO_AND                                       = 10677,  -- I have nothing to tell you. Go, and take that old toolbox with you.
        AH_NOW_I_UNDERSTAND                                                     = 10678,  -- Ah, now I understand...
        IS_THAT_WHY_YOU_DON_T_LIKE_TALKING                                      = 10679,  -- Is that why you don't like talking about the past, then, Babenn?
        BUT_IT_S_BEEN_MORE_THAN_A_HUNDRED                                       = 10680,  -- But it's been more than a hundred and fifty years. Don't you think it's time you told your story?
        GUMBAH_WHAT_ARE_YOU_DOING_HERE                                          = 10681,  -- Gumbah... What are you doing here?
        YOU_MUST_VE_FIGURED_IT_OUT_BY_NOW                                       = 10682,  -- You must've figured it out by now, right? Galka in Bastok have two names.
        ONE_IS_OUR_GIVEN_NAME_THE_OTHER_A                                       = 10683,  -- One is our given name. The other...a name that Humes give us if they can't pronounce the first one.
        VIGILANT_OWL_THAT_WAS_WHAT_THEY_CALLED_YOU                              = 10684,  -- Vigilant Owl...that was what they called you, wasn't it, Babenn? You've told me before...and I haven't forgotten.
        MEDDLING_CHILD_THAT_WAS_MORE_THAN_A_CENTURY                             = 10685,  -- Meddling child... That was more than a century ago. That name belongs in the past.
        WAIT_WHO_S_THERE_SHOW_YOURSELF                                          = 10686,  -- Wait... Who's there? Show yourself!
        MY_GREAT_GRANDFATHER_DID_NOT_FORGET_SIR_VIGILANT                        = 10687,  -- My great-grandfather did not forget, Sir Vigilant Owl... No, Sir Babenn.
        OMRAN_NO_YOU_CANNOT_BE_HIM_HUMES_DO                                     = 10688,  -- Omran...!? No, you cannot be him. Humes do not live longer than a hundred years.
        OMRAN_WAS_MY_GREAT_GRANDFATHER_HE_USED_TO                               = 10689,  -- Omran was my great-grandfather. He used to tell me about the mines when I was young...but whenever he did, it was with sadness and regret.
        HE_OFTEN_SAID_IF_YOU_MANAGE_TO_ACHIEVE                                  = 10690,  -- He often said: If you manage to achieve anything worthwhile in life, it is because you were lucky enough to have met the best people anyone could meet.
        OMRAN_SAID_THAT                                                         = 10691,  -- Omran said that?
        LISTEN_AND_REMEMBER_HEIR_TO_OMRAN_IN_THOSE                              = 10692,  -- Listen and remember, heir to Omran. In those days, Humes were in need of pride. Pride in having dug a mine without anyone else's help.
        MY_NAME_HAD_NO_PLACE_ON_THEIR_MONUMENT                                  = 10693,  -- My name had no place on their monument, and this I accepted.
        SOME_NEED_THEIR_ACHIEVEMENTS_CARVED_IN_STONE_EVEN                       = 10694,  -- Some need their achievements carved in stone, even though stone can weather and fade. It was a small price I paid for their fame.
        NO_MY_GREAT_GRANDFATHER_DID_NOT_SEEK_FAME                               = 10695,  -- No! My great-grandfather did not seek fame!
        HE_USED_TO_TELL_ME_THE_DAYS_HE                                          = 10696,  -- He used to tell me the days he spent digging those mines were the best of his life!
        ENOUGH_YOU_KNOW_AS_WELL_AS_I_DO                                         = 10697,  -- Enough. You know as well as I do that Galka and Humes do not live in the same flow of time.
        ID_10698                                                                = 10698,  -- ...
        BUT_I_CAN_TELL_YOU_ONE_THING_A                                          = 10699,  -- But I can tell you one thing. A hundred and fifty years ago, during those few days when we sought for mythril in the cold, dark tunnels...we saw the world with the same eyes.
        AND_THAT_TO_ME_IS_ENOUGH_NO_MATTER                                      = 10700,  -- And that, to me, is enough. No matter what people say, and even if the others are long gone, my memories are still with me.
        HEIR_TO_OMRAN_SEEK_NOT_THE_TRUENESS_OF                                  = 10701,  -- Heir to Omran, seek not the trueness of our bond in days long past, but that of bonds you share with others in this time, in this world.
        I_UNDERSTAND_FAREWELL_SIR                                               = 10702,  -- ...I understand. Farewell, sir.
        THAT_WAS_PRETTY_COMPLICATED_I_REALLY_HOPE_HE                            = 10703,  -- That was pretty complicated... I really hope he understood.
        YOU_RE_THE_ONE_WHO_COMPLICATED_MATTERS_YOU                              = 10704,  -- You're the one who complicated matters. You brought him here, did you not?
        AND_WHERE_DID_YOU_HEAR_ABOUT_MY_PAST                                    = 10705,  -- And where did you hear about my past? I don't remember telling you.
        OH_REALLY_THAT_S_WEIRD_UH_I_THINK                                       = 10706,  -- Oh, really? That's weird... Uh...I think Werei told me, yeah.
        ANYWAYS_I_GOTTA_RUN_BYE                                                 = 10707,  -- Anyways, I gotta run! Bye!
        IT_SEEMS_I_OWE_YOU_AN_APOLOGY_THIS                                      = 10708,  -- It seems I owe you an apology. This is for bringing my old toolbox back to me. Take it.
        HMM_WHAT_IS_IT_YOU_WANT_WITH_AN_2                                       = 10709,  -- Hmm? What is it you want with an old Galka like me?
        NOTHING_OF_VALUE_HAS_BEEN_PUT_UP_FOR                                    = 10710,  -- Nothing of value has been put up for sale in the auctions lately. The Quadav's influence on Bastok's mine digs may be more severe than I thought.
        WAHID_AT_YOUR_SERVICE_I_AM_A_COLLECTOR                                  = 10711,  -- Wahid, at your service. I am a collector of precious gems.
        MIND_YOU_I_AM_NOT_INTERESTED_IN_STONES                                  = 10712,  -- Mind you, I am not interested in stones with only monetary value. Gems of legend, with value that cannot be weighed in gold...those, a true collector seeks.
        CURRENTLY_I_AM_SEEKING_A_STONE_CALLED_IT                                = 10713,  -- Currently, I am seeking a stone called %. It is said that one can occasionally find these on the shores of the rivers in the Gustaberg Mountains.
        THEY_ARE_QUITE_HARD_TO_FIND_I_HEAR                                      = 10714,  -- They are quite hard to find, I hear, so search thoroughly.
        WHAT_S_MORE_I_HAVE_HEARD_ACCOUNTS_OF                                    = 10715,  -- What's more, I have heard accounts of people trying to pick one up, only to have it slip through their fingers and flow down the river once more.
        MANY_ADVENTURERS_LIKE_YOURSELF_HAVE_TRIED_THEIR_HAND                    = 10716,  -- Many adventurers like yourself have tried their hand, so to speak, but they all came back...well, empty-handed. I heard that those of great mettle had an especially hard time.
        THERE_ONCE_WAS_A_BARD_WHO_MANAGED_TO                                    = 10717,  -- There once was a bard who managed to bring one back...but he said that it would be the first and last time for him. Whether he was unable or unwilling to go back, I do not know.
        FROM_WHAT_I_VE_HEARD_HE_NOW_SPENDS                                      = 10718,  -- From what I've heard, he now spends his time singing in a tavern somewhere...
        AT_ANY_RATE_IF_YOU_GO_TO_THE                                            = 10719,  -- At any rate, if you go to the river and find one for me, I will give you a reward.
        OH_HO_GOOD_WORK                                                         = 10720,  -- Oh-ho! %! Good work!
        YES_YES_LOOK_HOW_IT_GLITTERS_MARVELOUS_SIMPLY                           = 10721,  -- Yes, yes! Look how it glitters! Marvelous, simply marvelous! If you find any more, come to me and I will reward you handsomely!
        MY_MOM_S_THE_GREATEST_ADVENTURER_EVER_EVERY                             = 10722,  -- My mom's the greatest adventurer ever! Every time she comes back, she brings me lots of neat gifts!
        WALK_DOWN_THIS_ROAD_TO_GO_TO_THE                                        = 10723,  -- Walk down this road to go to the Markets District. This is also the road for the Metalworks and the Port District.
        MOM_SAYS_IT_S_DANGEROUS_IN_THERE_AND                                    = 10724,  -- Mom says it's dangerous in there, and I can't go in...
        BUT_SOMEDAY_I_WILL_GO_INSIDE_EVERYONE_KNOWS                             = 10725,  -- But someday, I will go inside! Everyone knows that when grown-ups say that kind of thing, they're just trying to keep a fun place to themselves!
        AFTER_A_GALKA_LIVES_FOR_MORE_THAN_TWO                                   = 10726,  -- After a Galka lives for more than two hundred years, he reincarnates. Unfortunately, he retains no memory of his past life. But every generation, there is one Galka who does.
        HE_REMEMBERS_EVERYTHING_ABOUT_HIS_PAST_AND_HE                           = 10727,  -- He remembers everything about his past, and he becomes the Talekeeper, the leader of all Galka. Alas, we lost our Talekeeper thirty years ago.
        I_HAVE_LIVED_MORE_THAN_TWO_HUNDRED_YEARS                                = 10728,  -- I have lived more than two hundred years, but I have yet to see any improvement in our relationship with the Humes of Bastok.
        THE_LOSS_OF_OUR_TALEKEEPER_HAS_ONLY_WORSENED                            = 10729,  -- The loss of our Talekeeper has only worsened things... It has cast a dark shadow over the hearts of all Galka.
        MOST_GALKA_AROUND_HERE_DON_T_LIKE_HUMES                                 = 10730,  -- Most Galka around here don't like Humes much.
        THAT_S_WHY_WE_DON_T_CALL_OURSELVES                                      = 10731,  -- That's why we don't call ourselves by the names Humes give us.
        WEREI_WAS_THE_OLDEST_GALKA_AROUND_HERE_HE                               = 10732,  -- Werei was the oldest Galka around here. He was really strong when he was young, you know.
        HE_S_THE_ONE_WHO_TAUGHT_IRON_EATER                                      = 10733,  -- He's the one who taught Iron Eater, the only Galka in the Mythril Musketeers, how to fight.
        THIS_AREA_IS_OFF_LIMITS                                                 = 10734,  -- This area is off-limits.
        YOU_RE_HERE_FOR_THE_STAMP_HUNT_RIGHT                                    = 10735,  -- You're here for the stamp hunt, right? Here you go. I wonder why so many adventurers are participating in this thing. But then again, I wouldn't want children running around here, either.
        EVEN_WITH_ALL_OF_BASTOK_S_VAUNTED_TECHNOLOGICAL                         = 10736,  -- Even with all of Bastok's vaunted technological progress, chocobos, especially of the San d'Orian variety, are still favored by adventurers as rides.
        AND_OF_COURSE_OUR_CHOCOBOS_ARE_IMPORTED_DIRECTLY                        = 10737,  -- And of course, our chocobos are imported directly from San d'Oria!
        TWENTY_YEARS_AGO_THERE_WAS_A_WAR_BETWEEN                                = 10738,  -- Twenty years ago, there was a war between us and the beastmen. Captain Volker of the Mythril Musketeers and Chief Engineer Cid became heroes in that war...
        BUT_THAT_IS_HUME_HISTORY_FEW_BUT_US                                     = 10739,  -- But that is Hume history. Few but us know that we lost our best swordsman, the dark knight Zeid, during that conflict. He still hasn't been found, either alive or dead.
        OF_COURSE_TO_HUMES_IT_S_JUST_A                                          = 10740,  -- Of course, to Humes, it's just a historical detail, soon forgotten.
        THE_LOSS_OF_TALEKEEPER_RAOGRIMM_THIRTY_YEARS_AGO                        = 10741,  -- The loss of Talekeeper Raogrimm thirty years ago, and the more recent loss of Zeid, have struck us hard in this time of need.
        WE_GALKA_ARE_INHERENTLY_UNITED_BY_THE_PRESENCE                          = 10742,  -- We Galka are inherently united by the presence of our Talekeeper. With him absent, we are like a shipwrecked crew, lost and drifting in the dark...
        BASTOK_IS_A_SCARY_WARY_PLACE_OPEN_WARFARE                               = 10743,  -- Bastok is a scary-wary place! Open warfare with the Quadav! Everyone fighting!
        WINDURST_IS_SO_DIFFERENT_VERY_PEACEFUL_WE_BASH                          = 10744,  -- Windurst is so different! Very peaceful! We bash-mash Yagudo sometimes, yes, but at least we try to talk to them first!
        KILLING_EACH_OTHER_ISN_T_THE_WAY_MY                                     = 10745,  -- Killing each other isn't the way! My little-brittle bones are shaking!
        BASTOKERS_ARE_ALWAYS_GRUMPY_FRUMPY_BECAUSE_THEY_RE                      = 10746,  -- Bastokers are always grumpy-frumpy because they're fighting all the time!
        HONESTLY_SPEAKING_THE_GALKA_IN_THIS_DISTRICT_SCARE                      = 10747,  -- Honestly speaking, the Galka in this district scare me the most, even more so than the Quadav...
        OOPSY_DOOPSY_THAT_WAS_NOT_A_NICE_THING                                  = 10748,  -- Oopsy-doopsy. That was not a nice thing for me to say! Please don't tell anyone I said that!
        WHAT_THE_GUSGEN_MINES_OH_YOU_WANT_TO                                    = 10749,  -- What? The Gusgen Mines? Oh, you want to know about glocolite.
        I_SHOULD_WARN_YOU_IT_S_NOT_WORTH                                        = 10750,  -- I should warn you, it's not worth the risk. But you're on official business, right?
        THERE_ARE_POOLS_OF_GROUNDWATER_IN_THOSE_MINES                           = 10751,  -- There are pools of groundwater in those mines. A special monster lives in one of them, but you'll have to lure it out.
        TRADE_SOME_BAIT_TO_A_SPECIAL_SPOT_ON                                    = 10752,  -- Trade some bait to a special spot on the ground, and it'll come.
        IT_LIKES_SO_USE_ONE_OF_THOSE_ALL                                        = 10753,  -- It likes %, so use one of those. All you have to do is defeat it and you'll get your %. There are a lot of rivers there, mind you, but only one spot where it appears. Anyway, good luck!
        I_THOUGHT_I_TOLD_YOU_I_DON_T                                            = 10754,  -- I thought I told you I don't want any help, I-- Oh, I'm sorry. I thought you were someone else. She won't stop pestering me...
        HIYA_MISTER_PAVVKE_HOW_S_YOUR_HEALTH                                    = 10755,  -- Hiya, Mister Pavvke! How's your health?
        I_KNEW_YOU_D_BE_BACK_I_MIGHT                                            = 10756,  -- I knew you'd be back... I might be old, but I'm not dying yet.
        OOPS_SORRY_THAT_WAS_PARRAGGOH                                           = 10757,  -- Oops, sorry. That was Parraggoh...
        ANYWAY_I_WENT_AND_ASKED_ADVENTURERS_NEAR_THE                            = 10758,  -- Anyway, I went and asked adventurers near the Metalworks if they'd ever seen the % you told me about, but no one knew anything about them.
        THAT_S_VERY_KIND_OF_YOU_BUT_IT                                          = 10759,  -- That's very kind of you, but it's been over fifteen years since the accident... I have to face the fact that my friends, and their belongings, are gone forever.
        NO_DON_T_GIVE_UP_I_M_SURE                                               = 10760,  -- No, don't give up! I'm sure we'll find something!
        ID_10761                                                                = 10761,  -- ...
        HEY_HAVE_YOU_EVER_BEEN_TO_THE_PALBOROUGH                                = 10762,  -- Hey, have you ever been to the Palborough Mines? Did you see any % lying around?
        I_USED_TO_WORK_IN_THE_PALBOROUGH_MINES                                  = 10763,  -- I used to work in the Palborough Mines with many other Galka. Twenty years ago, an explosive went off before we'd cleared the tunnels, and suddenly we were surrounded by Quadav.
        MANY_GALKA_DIED_THAT_DAY_I_AM_LOOKING                                   = 10764,  -- Many Galka died that day... I am looking for their %. The fallen need to be remembered.
        I_M_KIND_OF_A_BASTOKAN_HISTORY_BUFF                                     = 10765,  -- I'm kind of a Bastokan history buff, and Mister Pavvke's been teaching me a lot. But when he told me about the Palborough Mines... I had to try helping him.
        IF_YOU_FIND_ANY_COULD_YOU_BRING_THEM                                    = 10766,  -- If you find any %, could you bring them to him? I'll pay you, of course.
        NO_CORNELIA_YOU_SHOULDN_T_I_COULDN_T                                    = 10767,  -- No, Cornelia, you shouldn't. I couldn't ask that of you. I will pay the reward myself.
        ALL_RIGHT_WELL_I_SHOULD_GO_TALK_TO                                      = 10768,  -- ...All right. Well, I should go talk to some more adventurers. One of them is bound to know something!
        SIGH_IT_S_NOT_THAT_I_DON_T                                              = 10769,  -- <Sigh> It's not that I don't appreciate it, but she shouldn't involve herself in other people's business like this...
        Y_YOU_VE_FOUND_IN_THE_PALBOROUGH_MINES                                  = 10770,  -- Y-you've found %! In the Palborough Mines, yes?
        THANK_YOU_YOU_DON_T_KNOW_WHAT_THIS                                      = 10771,  -- Thank you! You don't know what this means to me.
        THERE_SHOULD_BE_OTHERS_WHERE_YOU_FOUND_THIS                             = 10772,  -- There should be others where you found this one. If you find them, please bring them to me. I'm sorry I can't give you much, but here's your reward.
        I_M_GLAD_YOU_FOUND_IT_I_KNEW                                            = 10773,  -- I'm glad you found it! I knew you would! What? Why am I out here?
        WELL_MISTER_PAVVKE_WOULD_PROBABLY_SCOLD_ME_IF                           = 10774,  -- Well, Mister Pavvke would probably scold me if I tried to give you a reward. He'd say something like, she should not be meddling in our affairs...
        I_KNOW_I_KNOW_HE_S_RIGHT_BUT                                            = 10775,  -- I know, I know. He's right. But I can't help it. Whenever I decide to do something, I just can't think of anything else.
        YOU_KNOW_SOMETHING_THE_MORE_I_LISTEN_TO                                 = 10776,  -- You know something? The more I listen to Mister Pavvke's stories, the more I can see the gap in understanding between the Galka and Humes.
        BUT_THE_GALKA_SHOULDN_T_BE_BLAMED_FOR                                   = 10777,  -- But the Galka shouldn't be blamed for that, you know? Humes haven't exactly been nice to them, putting them to work and all... Most of the people who died in the accident Mister Pavvke was caught in were Galka, too.
        I_WISH_I_COULD_SOMEHOW_BRIDGE_THE_GAP                                   = 10778,  -- I wish I could somehow bridge the gap between the Galka and Humes... Well then! Enough talk, I have to go. See you around!
        OH_A_PRRRESENT_FROM_MOM_THANK_YOU_FOR                                   = 10779,  -- Oh! A prrresent from Mom! Thank you for bringing it!
        WAIT_DON_T_GO_YET_HERE_COULD_YOU                                        = 10780,  -- Wait, don't go yet! Here, could you give this to Mom? Please?
        A_PRESENT_FOR_MOM_UMM_I_THINK_SHE                                       = 10781,  -- A present for Mom? Umm... I think she should be home soon.
        HEY_KITTEN_I_M_HOME                                                     = 10782,  -- Hey kitten, I'm home!
        MOM_THIS_STRANGER_S_BROUGHT_A_PRRRESENT_FOR                             = 10783,  -- Mom! This stranger's brought a prrresent for you!
        A_PRESENT_OH_RIGHT_YOU_WENT_TO_THE                                      = 10784,  -- A present? Oh, right! You went to the Konschtat Highlands, then? What did you find? C'mon, show me!
        HUH_DOESN_T_LOOK_LIKE_ANYONE_FAMOUS_PAINTED                             = 10785,  -- Huh? %? Doesn't look like anyone famous painted it, either...
        MOM_IF_YOU_DON_T_WANT_IT_CAN                                            = 10786,  -- Mom? If you don't want it, can I have it? I like it! It's prrretty!
        OF_COURSE_DARLING_HERE_WELL_AT_LEAST_MY                                 = 10787,  -- Of course, darling. Here. Well, at least my daughter's happy. I'm sorry, but for something like that, I can't pay you more than this...
        HI_YOU_KNOW_WE_ALSO_HAD_A_VISITOR                                       = 10788,  -- Hi! You know, we also had a visitor before Werei left...
        I_APOLOGIZE_FOR_BOTHERING_YOU_AGAIN_I_WISHED                            = 10789,  -- I apologize for bothering you again. I wished to speak with you about Zeid...
        HEY_WEREI_THE_MUSKETEER_S_BACK_AGAIN                                    = 10790,  -- Hey, Werei? The Musketeer's back again.
        CAPTAIN_VOLKER_WE_GALKA_WOULD_ALSO_LIKE_TO                              = 10791,  -- Captain Volker... We Galka would also like to know of Zeid's whereabouts, but none of us knows where he might be.
        YOU_MUST_UNDERSTAND_I_CANNOT_CONTINUE_TO_PERFORM                        = 10792,  -- You must understand, I cannot continue to perform my duties with a clear conscience unless I know what became of him. As you know, Zeid is the one who should be leading the Mythril Musketeers, not I.
        IS_IT_YOUR_UNCLE_YOU_THINK_OF_WHEN                                      = 10793,  -- Is it your uncle you think of when you say this? True, many Galka were upset by his appointment as Captain after Raogrimm disappeared, but...
        WE_DO_NOT_FEEL_THE_SAME_WAY_ABOUT                                       = 10794,  -- We do not feel the same way about you. As Zeid is different from Raogrimm, you are very different from your uncle.
        IT_IS_NOT_BECAUSE_OF_MY_UNCLE_SIR                                       = 10795,  -- ...It is not because of my uncle, sir.
        I_AM_GLAD_TO_HEAR_THAT_I_NOW                                            = 10796,  -- I am glad to hear that. I now feel safe in telling you that a dark knight was sighted in the Palborough Mines. He was very powerful, I am told.
        THEN_IT_IS                                                              = 10797,  -- Then it is...?
        THAT_IS_ALL_I_KNOW                                                      = 10798,  -- That is all I know.
        SO_WHY_ARE_THERE_LESS_DARK_KNIGHTS_SINCE                                = 10799,  -- So...why are there less dark knights since Zeid disappeared? Any idea?
        WELL_ZEID_DID_IN_A_SENSE_CREATE_HIS                                     = 10800,  -- Well... Zeid did, in a sense, create his own version of the art, passed down since the glory days of Altepa. And it is not something one can master with skill alone.
        IT_IS_SAID_THAT_ONLY_THE_FEW_WHO                                        = 10801,  -- It is said that only the few who can tame the dark flames that burn within their soul, feeding on their sorrow and hatred...are chosen.
        THAT_S_ONE_OF_THE_LAST_THINGS_I                                         = 10802,  -- ...That's one of the last things I remember Werei saying. Say, why don't you go find Zeid yourself? Maybe he can teach you how to become a dark knight, too.
        THOUGH_WEREI_ONCE_TOLD_ME_THAT_THE_ROAD                                 = 10803,  -- Though Werei once told me that the road to becoming one is not an easy one to take.
        WHAT_TO_DO_WHAT_TO_DO_AH_AN                                             = 10804,  -- What to do, what to do? Ah, an adventurer! Could you help out a lowly trader? I'm working as an intermediary between the Metalworks and the Alchemists' Guild.
        I_M_SUPPOSED_TO_GET_THEM_SOME_MATERIALS                                 = 10805,  -- I'm supposed to get them some materials for this collaborative project they're working on, and I got everything except for %.
        SOUNDS_EASY_RIGHT_I_ONLY_HAVE_TO_FILL                                   = 10806,  -- Sounds easy, right? I only have to fill % with water from the Drachenfall in North Gustaberg.
        THE_PROBLEM_IS_I_CAN_T_FIND_A                                           = 10807,  -- The problem is, I can't find a place where I can get close enough to the falls to scoop some water up. Would you mind going in my place? Here, I'll give you %.
        OH_IT_S_YOU_DID_YOU_LOSE_THE                                            = 10808,  -- Oh, it's you. Did you lose the %? Here, I'll give you another one. Don't lose it this time.
        YOU_GOT_IT_THANK_THE_HEAVENS_YOU_SAVED                                  = 10809,  -- You got it! Thank the heavens! You saved my neck! Here, take this, you deserve it!
        HUME_BIGWIGS_DON_T_BOTHER_COMIN_AROUND_HERE                             = 10810,  -- Hume bigwigs don't bother comin' around here, so traders like me can go about their business all unconstrained-like. Heh-heh.
        THE_WORKERS_IN_THE_MINES_AND_THOSE_WHO                                  = 10811,  -- The workers in the mines and those who went out to avenge them...many of my brethren were slain by the Quadav.
        I_WANT_THE_QUADAV_TO_PAY_FOR_WHAT                                       = 10812,  -- I want the Quadav to pay for what they did, so that the souls of my fallen comrades may rest in peace.
        I_WANT_YOU_TO_GO_TO_THE_QUADAV                                          = 10813,  -- I want you to go to the Quadav stronghold in Beadeaux and kill as many of them as you can. Bring me back % as proof of your deeds, and I will reward you.
        GOOD_WORK_NOW_THE_SOULS_OF_MY_BRETHREN                                  = 10814,  -- Good work. Now the souls of my brethren can finally rest in peace.
        THE_GOVERNMENT_WON_T_DO_ANYTHING_ABOUT_THE                              = 10815,  -- The government won't do anything about the monsters in the Zeruhn Mines. It's not cost-effective. But those things always get in the way of work, you know?
        IF_YOU_CAN_GO_IN_THERE_AND_KILL                                         = 10816,  -- If you can go in there and kill a few, my buddies and I will put together a reward for you. Oh, and don't forget to bring me three % as proof you did the job.
        GOOD_WORK_WE_COULD_USE_MORE_PEOPLE_LIKE                                 = 10817,  -- Good work! We could use more people like you!
        SORRY_I_DON_T_HAVE_ANYTHING_TO_SELL                                     = 10818,  -- Sorry, I don't have anything to sell you. I'm trying to start a business selling goods from Ronfaure, but it's not easy getting stuff from areas that aren't under Bastokan control.
        SORRY_I_DON_T_HAVE_ANYTHING_TO_SELL_2                                   = 10819,  -- Sorry, I don't have anything to sell you. I'm trying to start a business selling goods from Fauregandi, but it's not easy getting stuff from areas that aren't under Bastokan control.
        SORRY_I_DON_T_HAVE_ANYTHING_TO_SELL_3                                   = 10820,  -- Sorry, I don't have anything to sell you. I'm trying to start a business selling goods from Norvallen, but it's not easy getting stuff from areas that aren't under Bastokan control.
        SORRY_I_DON_T_HAVE_ANYTHING_TO_SELL_4                                   = 10821,  -- Sorry, I don't have anything to sell you. I'm trying to start a business selling goods from Valdeaunia, but it's not easy getting stuff from areas that aren't under Bastokan control.
        SORRY_I_DON_T_HAVE_ANYTHING_TO_SELL_5                                   = 10822,  -- Sorry, I don't have anything to sell you. I'm trying to start a business selling goods from Li'Telor, but it's not easy getting stuff from areas that aren't under Bastokan control.
        HEY_YOU_RE_AN_ADVENTURER_RIGHT_COULD_YOU                                = 10823,  -- Hey, you're an adventurer, right? Could you take this note to my husband? He forgot to take it with him.
        MY_HUSBAND_S_NAME_IS_ZELMAN_YOU_LL                                      = 10824,  -- My husband's name is Zelman. You'll find him in the Zeruhn Mines. He's a miner. All right, then, off you go!
        WHAT_HE_THINKS_DOING_THE_GROCERIES_ISN_T                                = 10825,  -- What? He thinks doing the groceries isn't dignified? Ha! That's a laugh! And just who does he think's putting food on the table while he's off taking naps in that little hole of his!?
        YOU_BOUGHT_THIS_DIDN_T_YOU_HMM_I                                        = 10826,  -- You bought this, didn't you? Hmm... I was going to give this present to my husband, since he needed some cheering up lately, but...
        SINCE_YOU_DID_HIS_CHORES_FOR_HIM_IT                                     = 10827,  -- Since you did his chores for him, it's yours. Well, he always wanted to be an adventurer himself, so he should be happy knowing you have it.
        AH_DID_YOU_FIND_MY_HUSBAND_GOOD_I                                       = 10828,  -- Ah, did you find my husband? Good. I keep telling him to check his pockets before he leaves, but he never does. Anyway, here, take this. For your trouble.
        MY_HUSBAND_USED_TO_LISTEN_TO_ME_A                                       = 10829,  -- My husband used to listen to me a lot more when we were young. It'd be funny if he was going through a rebellious phase at his age!
        WHAT_DO_YOU_WANT_OH_YOU_THINK_BECAUSE                                   = 10830,  -- What do you want? Oh, you think because I'm just a kid you can walk over and talk to me for no good reason?
        TRUE_I_MIGHT_LOOK_LIKE_A_CHILD_NOW                                      = 10831,  -- True, I might look like a child now, but I know I was once a great warrior, and I can prove it.
        DO_YOU_WANT_TO_SEE_PROOF_YES_NO                                         = 10832,  -- Do you want to see proof? Yes. No.
        I_WASN_T_GOING_TO_SHOW_YOU_ANYWAY                                       = 10833,  -- I wasn't going to show you anyway. I know your type. Patting kids on the head and thinking how great life was when you were their age, right? Spare me, please.
        I_THOUGHT_SO_WELL_ALL_RIGHT_HERE_BUT                                    = 10834,  -- I thought so. Well...all right, here. But be careful! It's very, very valuable--it's a piece of my past life.
        A_FRIEND_GAVE_THIS_TO_ME_OVER_TWENTY                                    = 10835,  -- A friend gave this to me over twenty years ago. I can't remember what it all means, though.
        I_SHOWED_THIS_TO_MY_FRIEND_GUMBAH_ONCE                                  = 10836,  -- I showed this to my friend Gumbah once, and his opinion was that this is a very valuable document that tells you each monster type's weakness.
        HE_SAID_IT_WILL_COME_IN_HANDY_WHEN                                      = 10837,  -- He said it will come in handy when I become an adventurer.
        YOU_VE_BEEN_A_GOOD_PUPIL_COME_BACK                                      = 10838,  -- You've been a good pupil. Come back anytime if you want to see it again. Well, at least until I leave on my first adventure...
        YOU_CAN_T_FISH_HERE                                                     = 10839,  -- You can't fish here.
        YOU_CAN_T_FISH_WITHOUT_A_ROD_IN                                         = 10840,  -- You can't fish without a rod in your hands.
        YOU_CAN_T_FISH_WITHOUT_BAIT_ON_THE                                      = 10841,  -- You can't fish without bait on the hook.
        YOU_CAN_T_FISH_AT_THE_MOMENT                                            = 10842,  -- You can't fish at the moment.
