        THERE_IS_NO_LONGER_ANY_NEED_TO_SEARCH                                   = 11533,  -- There is no longer any need to search for Sir Raogrimm, Zeid, or Werei. Our Talekeeper has finally returned!
        NOW_IS_THERE_A_PLACE_WHERE_THE_TALEKEEPER                               = 11534,  -- Now, is there a place where the Talekeeper may rest? He is exhausted from his journey.
        IT_IS_NORMALLY_OFF_LIMITS_BUT_I_FEEL                                    = 11535,  -- It is normally off-limits, but I feel we can make an exception and open up the restricted area on Ore Street. Using an inn would only cause commotion among the city residents.
        VERY_WELL_LEAD_US_TO_THIS_RESTRICTED_AREA                               = 11536,  -- Very well. Lead us to this restricted area.
        AND_THAT_IS_WHAT_I_SAW_TO_TELL                                          = 11537,  -- And that is what I saw. To tell you the truth, I'm confused. I should be happy to see the return of the Talekeeper, but something tells me there's more to this story...
        AND_NOW_THERE_IS_TALK_OF_SENDING_A                                      = 11538,  -- And now there is talk of sending a party to investigate the Altepa Desert, but you should talk to Drake Fang in the Zeruhn Mines about that.
        WHAT_IS_THIS_YOU_WERE_TOLD_BY_SIR                                       = 11539,  -- What is this? You were told by Sir Iron Eater to bring this % back from the Altepa Desert?
        WAIT_HERE                                                               = 11540,  -- Wait here.
        WHAT_IS_THE_MEANING_OF_THIS_TALL_MOUNTAIN                               = 11541,  -- What is the meaning of this, Tall Mountain?
        OH_JUST_A_PERSONAL_REQUEST_I_D_LIKE                                     = 11542,  -- Oh, just a personal request. I'd like to see the % that our Talekeeper found when he was on his journey of rebirth.
        THE_MOONPEBBLE_IS_A_THING_OF_ALTEPAN_LEGEND                             = 11543,  -- The moonpebble is a thing of Altepan legend. It's not every day that one gets to lay their eyes on a Galkan treasure.
        ID_11544                                                                = 11544,  -- ...
        A_HAH_HAH_IS_THAT_ALL_WELL_NORMALLY                                     = 11545,  -- A-hah-hah. Is that all? Well, normally we wouldn't show it to just anyone, but because you have assisted us so much, I guess we can make an exception.
        I_SEE_THEN_IT_WAS_ALL_JUST                                              = 11546,  -- I see... Then it was all just...
        WHAT_DO_YOU_SEE_IT_WAS_ALL_JUST                                         = 11547,  -- What do you see? It was all just what?
        JUST_A_HOAX_THAT_IS_WHAT_YOU_MEANT                                      = 11548,  -- Just a hoax. That is what you meant to say, is it not, Tall Mountain?
        WH_WHO_ARE_YOU                                                          = 11549,  -- Wh-who are you!?
        I_GUESS_I_HAVE_MUCH_MORE_WORK_TO                                        = 11550,  -- I guess I have much more work to do to get the keeper of two hundred years of memories to remember my name.
        WHAT_BUSINESS_DOES_A_MYTHRIL_MUSKETEER_HAVE_HERE                        = 11551,  -- What business does a Mythril Musketeer have here? And how dare you call the Talekeeper a fake!
        THIS_ADVENTURER_HAS_SUCCEEDED_IN_BRINGING_BACK_A                        = 11552,  -- This adventurer has succeeded in bringing back a real %. And by the looks of it, even a guard could tell that yours was not the true one.
        NOT_THE_TRUE_ONE_HOW_DO_YOU_KNOW                                        = 11553,  -- Not the true one? How do you know that the adventurer's is not a fake? Eh!?
        HOW_COULD_A_HUME_TAMED_DOG_LIKE_YOU                                     = 11554,  -- How could a Hume-tamed dog like you even tell the difference between a simple rock and an authentic Galkan treasure!?
        ARE_YOU_FINISHED                                                        = 11555,  -- Are you finished?
        HELLO_THERE_TALEKEEPER                                                  = 11556,  -- Hello there, Talekeeper!
        GUMBAH                                                                  = 11557,  -- Gumbah?
        WH_WHO_ARE_YOU_2                                                        = 11558,  -- Wh-who are you?
        I_M_GUMBAH_I_JUST_CAME_BY_TO                                            = 11559,  -- I'm Gumbah. I just came by to meet the new Talekeeper.
        WOW_TWO_HUNDRED_YEARS_OF_GALKAN_MEMORIES_TO                             = 11560,  -- Wow. Two hundred years of Galkan memories to carry around. Gee, that must be pretty tough.
        UM_YEAH                                                                 = 11561,  -- Um...yeah...
        I_HEARD_FROM_MY_FRIEND_WEREI_THAT_TALEKEEPERS                           = 11562,  -- I heard from my friend Werei that Talekeepers, well, don't...
        REALLY_GET_TO_SEE_MANY_BIRTHDAYS_IF_YOU                                 = 11563,  -- ...really get to see many birthdays, if you know what I mean.
        ID_11564                                                                = 11564,  -- !!!
        I_DON_T_KNOW_IF_WEREI_MEANT_THAT                                        = 11565,  -- I don't know if Werei meant that the responsibilities of the title were the reason, or if it was just destiny...
        NOW_THAT_I_THINK_ABOUT_IT_THE_FORMER                                    = 11566,  -- Now that I think about it, the former Talekeeper, Raogrimm, also disappeared on a mission to the Northlands.
        THERE_S_NO_WAY_YOU_WOULD_CATCH_ME                                       = 11567,  -- There's no way you would catch me being a Talekeeper. I don't think I could handle it!
        WHAT_IS_HE_TALKING_ABOUT_MISTER_GABBOT_YOU                              = 11568,  -- What is he talking about, Mister Gabbot? You never told me anything about any dangerous missions. You just said if I stuck with you, I could get some delicious grilled mutton!
        SHUT_YOUR_MOUTH_YOU_IMBECILE_THEY_RE_TRYING                             = 11569,  -- Shut your mouth, you imbecile! They're trying to trick you!
        I_M_OUT_OF_HERE                                                         = 11570,  -- I'm out of here!
        HEY_WAIT                                                                = 11571,  -- Hey! Wait!
        I_WOULD_ADVISE_A_QUICK_DEPARTURE_FROM_THIS                              = 11572,  -- I would advise a quick departure from this city. And if I, or any of the guards, ever catch you back here again...
        YOU_WON_T_HAVE_TO_WORRY_ABOUT_THAT                                      = 11573,  -- You won't have to worry about that. I just didn't think you would all fall for my story so easily.
        I_DON_T_THINK_I_MADE_MYSELF_CLEAR                                       = 11574,  -- I don't think I made myself clear. Would you like my axe to clear things up for you?
        I_I_GET_THE_PICTURE                                                     = 11575,  -- I-I get the picture!
        I_DON_T_KNOW_I_THOUGHT_HE_HAD                                           = 11576,  -- I don't know. I thought he had potential...
        IT_IS_UNUSUAL_FOR_YOU_TO_GET_SO                                         = 11577,  -- It is unusual for you to get so upset, Gumbah.
        UPSET_I_WASN_T_UPSET_BUT_WHEN_HE                                        = 11578,  -- Upset? I wasn't upset. But when he said that we didn't need to search for Werei anymore...
        HOW_DARE_HE_SAY_SUCH_THINGS_ABOUT_MY                                    = 11579,  -- How dare he say such things about my friend.
        GUMBAH_2                                                                = 11580,  -- Gumbah...
        THIS_THIS_IS_A_LETTER_FROM_WEREI_YOU                                    = 11581,  -- This...this is a letter from Werei! You say some adventurer had it?
        WHY_WOULD_HE_DO_THIS_HE_COULD_HAVE                                      = 11582,  -- Why would he do this? He could have just talked to me...
        I_APOLOGIZE_FOR_LEAVING_WITHOUT_ANY_NOTICE_BUT                          = 11583,  -- I apologize for leaving without any notice, but I can assume that you were already aware of my approaching journey.
        EVEN_NOW_AS_I_WRITE_THIS_LETTER_I                                       = 11584,  -- Even now as I write this letter, I ponder over whether I should be sending it or not--whether this really is the best thing to do.
        GUMBAH_YOU_HAVE_ALWAYS_EMBRACED_YOUR_FREEDOM_WHILE                      = 11585,  -- Gumbah. You have always embraced your freedom while turning your cheek to any form of responsibility.
        HOWEVER_AMONG_MEN_WHO_PUT_TOO_MUCH_PRIDE                                = 11586,  -- However, among men who put too much pride in their race, you stand out as a light of reason.
        I_KNOW_HOW_YOU_MUST_FEEL_THE_SHOCK                                      = 11587,  -- I know how you must feel. The shock you received when you first realized the weight you must bear...
        THE_WEIGHT_THE_TALEKEEPER_MUST_BEAR                                     = 11588,  -- The weight the Talekeeper must bear...
        YOU_KNEW_WEREI_AND_YOU_DIDN_T_SAY                                       = 11589,  -- You knew, Werei! And you didn't say anything...
        YOU_THOUGHT_THAT_AFTER_TWO_HUNDRED_YEARS_OF                             = 11590,  -- You thought that after two hundred years of friendship, I wouldn't pick up on something as obvious as that?
        HOWEVER_I_RESPECT_YOUR_WILL_YOU_DID_NOT                                 = 11591,  -- However, I respect your will. You did not choose to bear the anger, pain, and suffering of the Galka people.
        AND_IT_IS_TRUE_THAT_THOSE_WHO_HAVE                                      = 11592,  -- And it is true that those who have been bestowed with this task--including Raogrimm--have always perished before setting out on their journey of rebirth.
        THAT_MAY_BE_DESTINY_SO_I_CAN_SEE                                        = 11593,  -- That may be destiny, so I can see why you would be afraid.
        BUT_LET_ME_SAY_ONE_THING_YOU_MAY                                        = 11594,  -- But let me say one thing. You may feel lost, but you must remember, there are things that only you can do.
        NOT_THAT_THE_TALEKEEPER_CAN_DO_BUT_THAT                                 = 11595,  -- Not that the Talekeeper can do, but that only you, Gumbah, can do. Do not forget this as you follow your path in life.
        ONLY_THEN_WILL_YOU_REALIZE_WHY_YOU_MUST                                 = 11596,  -- Only then will you realize why you must carry the two hundred years of Galkan memories.
        I_MUST_CONTINUE_ON_MY_JOURNEY_NOW_I                                     = 11597,  -- I must continue on my journey now. I am looking forward to the day when we can fight again, side by side. Do not forget, we shall always be friends.
        WEREI                                                                   = 11598,  -- Werei!
        YOU_CAN_COME_OUT_NOW_CORNELIA_I_KNOW                                    = 11599,  -- You can come out now, Cornelia. I know you're hiding there.
        SO_GUMBAH_WHAT_ARE_YOU_GOING_TO_DO                                      = 11600,  -- So, Gumbah, what are you going to do?
        DO_YOU_THINK_I_KNOW                                                     = 11601,  -- Do you think I know?
        BUT_I_KNOW_YOU_GUMBAH_AND_I_KNOW                                        = 11602,  -- But I know you, Gumbah, and I know that you aren't going to run away from your destiny, like I have from mine.
        YOU_RE_DIFFERENT_FROM_THE_REST_OF_US                                    = 11603,  -- You're different from the rest of us. No matter what you decide, I know that you'll face what lies before you. You're the one who taught me that.
        I_M_SORRY_I_THINK_I_JUST_NEED                                           = 11604,  -- I'm sorry... I think I just need to be alone...
        OKAY_GUMBAH                                                             = 11605,  -- Okay, Gumbah...
        WHY_ARE_ONLY_ADVENTURERS_ALLOWED_IN_THE_KORROLOKA                       = 11606,  -- Why are only adventurers allowed in the Korroloka Tunnel!? How long must we Galka live in the confines of that cramped Hume-hole!?
        WE_MINEWORKERS_REFUSE_TO_BE_TOOLS_OF_THE                                = 11607,  -- We mineworkers refuse to be tools of the government!
        YOU_ONLY_LET_ADVENTURERS_PASS_BECAUSE_THERE_S                           = 11608,  -- You only let adventurers pass because there's something down there you don't want us Galka to know about!
        WE_RE_SICK_OF_BEING_LIED_TO_BY                                          = 11609,  -- We're sick of being lied to by you Humes!
        H_HEY_CALM_DOWN_OKAY                                                    = 11610,  -- H-hey, calm down...okay?
        W_WE_RE_JUST_KEEPING_THE_TUNNEL_CLOSED                                  = 11611,  -- W-we're just keeping the tunnel closed to protect you...
        HUH_HOW_LONG_DO_YOU_THINK_YOU_CAN                                       = 11612,  -- Huh!? How long do you think you can fool us!?
        WHAT_IS_GOING_ON_HERE                                                   = 11613,  -- What is going on here!?
        SIR_IRON_EATER_YOU_MUST_DO_SOMETHING_IF                                 = 11614,  -- Sir Iron Eater! You must do something. If they would only open this tunnel to us, and not just adventurers, there wouldn't be any problem.
        DO_THESE_FOOLS_UNDERSTAND_WHAT_THEY_RE_SAYING                           = 11615,  -- Do these fools understand what they're saying?
        OH_IT_S_GUMBAH                                                          = 11616,  -- Oh! It's Gumbah!
        STOP_IT_ALL_OF_YOU                                                      = 11617,  -- Stop it! All of you!
        WHEN_ARE_YOU_GOING_TO_WAKE_UP_AND                                       = 11618,  -- When are you going to wake up and realize what you are doing is foolish!?
        WHAT_IS_AT_THE_END_OF_THE_KORROLOKA                                     = 11619,  -- What is at the end of the Korroloka Tunnel? You already know! Nothing but desert! Do you still wish to believe that that is where we belong?
        GET_OUT_OF_HERE_CHILD                                                   = 11620,  -- Get out of here, child!
        BIG_TALK_FOR_SUCH_A_LITTLE_KID_SO                                       = 11621,  -- Big talk for such a little kid! So, what are you saying? You've been there?
        ONE_HUNDRED_YEARS_AGO_I_HAVE                                            = 11622,  -- One hundred years ago...I have.
        ONE_HUNDRED_YEARS_AGO_YOU_VE_ONLY_BEEN                                  = 11623,  -- One hundred years ago!? You've only been around for twenty.
        WHEN_WEREI_AND_I_WERE_STILL_YOUNG_WE                                    = 11624,  -- When Werei and I were still young, we snuck by the guards...
        WHEN_WE_GOT_THROUGH_TO_THE_OTHER_SIDE                                   = 11625,  -- When we got through to the other side of the tunnel, all we saw was a vast desert and some sandy ruins.
        IS_THAT_WHAT_YOU_WANT_TO_CALL_HOME                                      = 11626,  -- Is that what you want to call home? Even if you were able to defeat the thousands of Antican warriors, would you really want to live in a place like that?
        BUT_DON_T_YOU_ALREADY_KNOW_THE_ANSWER                                   = 11627,  -- But don't you already know the answer? When did the Talekeeper have to start making the decisions for everyone?
        GUMBAH_3                                                                = 11628,  -- Gumbah...
        WAIT_YOU_CAN_T_BE                                                       = 11629,  -- Wait... You can't be...
        LET_ME_ASK_YOU_ARE_YOU_WILLING_TO                                       = 11630,  -- Let me ask you! Are you willing to go to battle with the Antica just to divert your anger from the Humes?
        LET_ME_ASK_YOU_DO_YOU_REALLY_THINK                                      = 11631,  -- Let me ask you! Do you really think that our home lies in that wasteland on the other side of this tunnel?
        LET_ME_ASK_YOU_DO_WE_GALKA_REALLY                                       = 11632,  -- Let me ask you! Do we Galka really need a Talekeeper to remember the past?
        YES_THERE_WILL_BE_DAYS_WHEN_CONFLICT_WILL                               = 11633,  -- Yes, there will be days when conflict will arise between us and the Humes. The world seen through their eyes is much different than the world seen through ours.
        HOWEVER_THE_SAME_IS_TRUE_FOR_ALL_GALKA                                  = 11634,  -- However, the same is true for all Galka. We all look at the world in a different way. No one in this world is exactly alike.
        BUT_THERE_IS_ONE_THING_THAT_CAN_BE                                      = 11635,  -- But there is one thing that can be said, and that is that we are all living together on this planet, Vana'diel. There is nothing that can change that.
        OF_COURSE_PEOPLE_ARE_GOING_TO_HAVE_DIFFERENT                            = 11636,  -- Of course people are going to have different morals and ideals, but we all must learn to live together. There is only one Vana'diel!
        THE_GALKA_FUTURE_DOES_NOT_LIE_OUT_IN                                    = 11637,  -- The Galka future does not lie out in a desert. Bastok is our home!
        RAOGRIMM_WEREI_ZEID_THEY_ARE_ALL_GONE_HOWEVER                           = 11638,  -- Raogrimm, Werei, Zeid...they are all gone. However, we no longer need a Talekeeper to remember our past. We can do it ourselves--together.
        THERE_IS_NO_REASON_FOR_ANY_OF_YOU                                       = 11639,  -- There is no reason for any of you to rely on a kid who had the rotten luck of getting stuck with two hundred years of memories.
        HOWEVER_IF_IT_WILL_HELP_I_WILL_TRY                                      = 11640,  -- However, if it will help, I will try to do anything that I can--even if it means keeping two centuries of memories.
        IF_THAT_WILL_SHOW_YOU_THAT_YOU_DON                                      = 11641,  -- If that will show you that you don't need a Talekeeper to live happy lives...
        GUMBAH_4                                                                = 11642,  -- Gumbah...
        HA_HA_IT_S_BEEN_A_WHILE_SINCE                                           = 11643,  -- Ha ha. It's been a while since I talked like an adult. It's pretty draining.
        NOW_YOU_CAN_REST_IN_PEACE_WEREI_RAOGRIMM                                = 11644,  -- Now you can rest in peace...Werei...Raogrimm...
        EVERYBODY_STILL_LOOKS_A_LITTLE_CONFUSED_THEY_DON                        = 11645,  -- Everybody still looks a little confused. They don't even know how to talk to me.
        WELL_I_DON_T_BLAME_THEM_THE_TALEKEEPER                                  = 11646,  -- Well, I don't blame them. The Talekeeper is supposed to be a great, sacred presence. I was probably the last person they'd expect to be the Talekeeper.
        BUT_THAT_S_OKAY_THEY_CAN_THINK_OF                                       = 11647,  -- But that's okay. They can think of me the way they always have--as an annoying little kid.
        I_M_NOT_GOING_TO_TREAT_HIM_ANY                                          = 11648,  -- I'm not going to treat him any different just because he's the Talekeeper. It must have been hard for him to keep it all inside like he did...
        BUT_ON_THE_INSIDE_HE_S_STILL_JUST                                       = 11649,  -- But on the inside, he's still just the jerk that I've known all along! He's not getting any special treatment from me!
        I_GET_IT_NOW_HE_WAS_ALWAYS_TALKING                                      = 11650,  -- I get it now! He was always talking like he was the best because he was the Talekeeper! Hah! Talekeepers--who needs 'em!
        I_GUESS_WE_CAN_NO_LONGER_LIVE_BY                                        = 11651,  -- I guess we can no longer live by those words anymore...but I never thought that it would be Gumbah who would teach us that.
        THERE_HAS_BEEN_SOME_COMMOTION_IN_THE_MINES                              = 11652,  -- There has been some commotion in the Mines District near Ore Street. People are saying that a new Talekeeper has appeared.
        IT_SOUNDS_FISHY_TO_ME_BUT_WITH_THE                                      = 11653,  -- It sounds fishy to me, but with the disappearance of their elder, Werei, anything could be possible. And the last thing we want is an uprising by the Galka.
        GO_TO_ORE_STREET_AND_TALK_TO_MEDICINE                                   = 11654,  -- Go to Ore Street and talk to Medicine Eagle. He says he was there when the commotion started.
        I_ASSUME_AN_ADVENTURER_OF_YOUR_CALIBER_HAS                              = 11655,  -- I assume an adventurer of your caliber has heard of Norg.
        WELL_THE_PLACE_IS_A_HAVEN_FOR_PIRATES                                   = 11656,  -- Well, the place is a haven for pirates. They even have ties with the Tenshodo. In any case, it's an area that cannot be looked upon lightly.
        THAT_IS_WHY_WE_WANT_YOU_TO_TRAVEL                                       = 11657,  -- That is why we want you to travel there as an emissary. Report to Sir Naji in the President's Office for details.
        CURRENTLY_CHIEF_ENGINEER_CID_IS_CONDUCTING_RESEARCH_ON                  = 11658,  -- Currently, Chief Engineer Cid is conducting research on the architecture in Ro'Maeve near the Sanctuary of Zi'Tah. Your next mission is to travel there and assist him.
        REPORT_TO_THE_CHIEF_ENGINEER_IN_THE_METALWORKS                          = 11659,  -- Report to the Chief Engineer in the Metalworks for further details.
        WE_ARE_SEARCHING_FOR_AN_ADVENTURER_HOLDING_VITAL                        = 11660,  -- We are searching for an adventurer holding vital information dealing with a certain national investigation.
        THE_PRESIDENT_HIMSELF_HAS_EXPRESSED_GREAT_INTEREST_IN                   = 11661,  -- The president himself has expressed great interest in this case. Proceed to the President's Office for the details of this mission.
        YOU_VE_BEEN_ORDERED_BY_THE_PRESIDENT_TO                                 = 11662,  -- You've been ordered by the president to deliver that %. When you have completed that task, you can return here for your next mission.
        IT_LOOKS_LIKE_BASTOK_IS_REALLY_GOING_TO                                 = 11663,  -- It looks like Bastok is really going to begin an investigation of the Galka homeland of Altepa.
        YOUR_ROLE_IN_THIS_INVESTIGATION_WILL_HAVE_YOU                           = 11664,  -- Your role in this investigation will have you traveling to the Quicksand Caves. Get the details of this mission from Iron Eater in the President's Office.
        AS_A_CONTINUATION_OF_BASTOK_S_INVESTIGATION_OF                          = 11665,  -- As a continuation of Bastok's investigation of Altepa, this time you will be traveling to Zepwell Island.
        YOU_WILL_BE_CARRYING_OUT_YOUR_PART_OF                                   = 11666,  -- You will be carrying out your part of the investigation in the Kuftal Tunnel, which connects Cape Teriggan to Zepwell Island. Report to Drake Fang in the Zeruhn Mines for details.
        SENATOR_ALOIS_HAS_ASKED_FOR_YOUR_ASSISTANCE                             = 11667,  -- Senator Alois has asked for your assistance.
        IT_IS_SOMETHING_ABOUT_AN_EXPEDITION_TO_VOLLBOW                          = 11668,  -- It is something about an expedition to Vollbow...
        I_JUST_HOPE_HE_S_NOT_ASKING_YOU                                         = 11669,  -- I just hope he's not asking you to go get lizard eggs again... Wait, you didn't hear me say that.
        RECENTLY_AN_ADVENTURER_WHO_WAS_SENT_TO_INVESTIGATE                      = 11670,  -- Recently, an adventurer who was sent to investigate the Northlands has been attacked.
        ACCORDING_TO_HER_REPORT_THE_ATTACKER_RESEMBLED_THE                      = 11671,  -- According to her report, the attacker resembled the dark knight Zeid.
        THE_STRANGE_THING_IS_THAT_THE_ATTACKER_PASSED                           = 11672,  -- The strange thing is that the attacker passed a letter to the adventurer before letting her go. Now, this letter's content is causing quite a commotion in the President's Office.
        YOU_HAVE_BEEN_ASKED_TO_REPORT_DIRECTLY_TO                               = 11673,  -- You have been asked to report directly to President Karst for further details.
        THE_MINSTREL_OF_MELODIES_IS_MY_NAME_FOR                                 = 11674,  -- The minstrel of melodies is my name, For a mere # gil I'll recall your past. Your stories of love, anger, triumph, and shame, The river of memories runs deep and vast.
        THE_MINSTREL_OF_MELODIES_IS_MY_NAME_FOR_2                               = 11675,  -- The minstrel of melodies is my name, For a mere # gil I'd recall your past. But I find that you're lacking in cash or in fame, So until that time, my kind offer will last.
        NOW_CLOSE_YOUR_EYES                                                     = 11676,  -- Now close your eyes...
        WHICH_MEMORY_WILL_YOU_HAVE_RECALLED_NOTHING_BASTOK                      = 11677,  -- Which memory will you have recalled? Nothing. Bastok Missions. Bastok Quests. Other Quests. Add-on Scenarios.
        WHICH_MEMORY_WILL_YOU_HAVE_RECALLED_NOTHING_FETICHISM                   = 11678,  -- Which memory will you have recalled? Nothing. Fetichism. To the Forsaken Mines. Return of the Talekeeper(pt.1). Return of the Talekeeper(pt.2). On My Way. Enter the Talekeeper.
        WHICH_MEMORY_WILL_YOU_HAVE_RECALLED_NOTHING_THE                         = 11679,  -- Which memory will you have recalled? Nothing. The Eleventh's Hour(pt.1). The Eleventh's Hour(pt.2). Fallen Comrades(pt.1). Fallen Comrades(pt.2). Rivals(pt.1). Rivals(pt.2). The Signpost Marks the Spot. Blade of Darkness. The Doorman. The Talekeeper's Truth(pt.1). The Talekeeper's Truth(pt.2). The Talekeeper's Truth(pt.3). The Talekeeper's Gift(pt.1). The Talekeeper's Gift(pt.2). Werei's Disappearance. Inheritance(pt.1). Inheritance(pt.2). Inheritance(pt.3). Out of the Depths. A Question of Faith(pt.1). A Question of Faith(pt.2). Fully Mental Alchemist(pt.1). Fully Mental Alchemist(pt.2). The Wondrous Whatchamacallit(pt.1). The Wondrous Whatchamacallit(pt.2).
        WHICH_MEMORY_WILL_YOU_HAVE_RECALLED_NOTHING_CHAMELEON                   = 11680,  -- Which memory will you have recalled? Nothing. Chameleon Capers. A Thief in Norg!? Dynamis - The Shrouded Land(pt.1). Dynamis - The Shrouded Land(pt.2). Dynamis Interloper. A Chocobo's Tale(pt.1). A Chocobo's Tale(pt.2). Corsair Attire(pt.1). Corsair Attire(pt.2).
        WHICH_MEMORY_WILL_YOU_HAVE_RECALLED_NOTHING_DRENCHED                    = 11681,  -- Which memory will you have recalled? Nothing. Drenched! It Began with a Raindrop. Hasten! In a Jam in Jeuno? The Gloom Phantom's Approach. The Brygid Cup. The Destiny Destroyers(pt.1). The Destiny Destroyers(pt.2). Best Served Cold(pt.1). Best Served Cold(pt.2). Raebrimm's Rebirth. Uran-Mafran of the Maelstrom. To Movalpolos! Odin's Eye. Moglesse Oblige. Your Decision.
        WOULD_YOU_BE_INTERESTED_IN_A_NICE_SUIT                                  = 11682,  -- Would you be interested in a nice suit of adventurer-issue armor? Be careful when you buy, though. We offer no refunds.
        I_GOT_NO_BUSINESS_WITH_A_FLEA_LIKE                                      = 11683,  -- I got no business with a flea like you. Get outta my face before I decide to messy-wess you up.
        YOU_RE_RIGHT_HA_HA_HA_I_KNEW                                            = 11684,  -- You're %, right? Ha ha ha! I knew it! Just like Gilgamesh described. Lemme tell you what I gotty-wot so far.
        THE_CREEPY_WEEP_THAT_STOLE_OUR_HELMET_ISN                               = 11685,  -- The creepy-weep that stole our helmet isn't from any large syndicate. He isn't even very famous among other pirates. He's just a simple thiefy-weef trying to pull off a big job for a big profit.
        ACCORDING_TO_THE_OWNER_OF_THAT_INN_HE                                   = 11686,  -- According to the owner of that inn, he traveled numerous timey-wimes between here and Selbina, and would sometimes talk about his plans after a few too many drinky-winks. But then one day, he just disappeared.
        AFTER_LOOKING_AT_NORG_S_NAUTICAL_LOGGY_WOGS                             = 11687,  -- After looking at Norg's nautical loggy-wogs, I learned that the time he disappeared matches the time he must have entered our headquarters. But where he went from therey-where, I don't know.
        WA_WA_WAIT_THERE_S_SOMETHING_ELSE                                       = 11688,  -- Wa-wa-wait! There's something else.
        ONE_OF_OUR_MEN_IN_BASTOK_IS_PIECING                                     = 11689,  -- One of our men in Bastok is piecing together all the information we've gathered so far. He's hiding out in a run-down old housey-wouse in the Mines District (J-6). He should be able to give you something juicy-wuicy.
        I_THOUGHT_THAT_THIS_MIGHT_HAVE_BEEN_THE                                 = 11690,  -- I thought that this might have been the work of some large groupy-woop, but when I heard that it was just one guy...boy, was I surprisey-wised!
        I_CAN_UNDERSTAND_WANTING_TO_MAKEY_WAKE_IT                               = 11691,  -- I can understand wanting to makey-wake it big overnight, but he should have thought a little bitty-wit longer before deciding to take us on!
        WOULD_YOU_MIND_LEAVING_ME_ALONE_I_HAVE                                  = 11692,  -- Would you mind leaving me alone? I have no time for small talk.
        YOU_ARE_ARE_YOU_NOT_I_HAVE_BEEN                                         = 11693,  -- You are %, are you not? I have been waiting for your arrival. I do not have much time, so I will keep this quick.
        THE_DAY_OF_THE_THEFT_THERE_WERE_NUMEROUS                                = 11694,  -- The day of the theft, there were numerous reports of a strange character wearing an even stranger helmet traveling on foot towards Zulkheim.
        I_JOURNEYED_HERE_FROM_SAN_D_ORIA_BUT                                    = 11695,  -- I journeyed here from San d'Oria, but heard nothing of such sightings on my way. This leaves the possibility that he may have turned back to Jeuno.
        I_FEEL_THAT_HE_MAY_STILL_BE_IN                                          = 11696,  -- I feel that he may still be in the area. I am going to continue my search here.
        AND_ONE_OTHER_THING                                                     = 11697,  -- And one other thing.
        ONE_MORE_OF_US_IS_STATIONED_IN_A                                        = 11698,  -- One more of us is stationed in a small, run-down building in the Bastok Mines (J-6). He may have some useful information.
        THE_TYPE_OF_HELMET_THAT_WAS_STOLEN_IS                                   = 11699,  -- The type of helmet that was stolen is known in the Far East as a kabuto. Many people find its design strange, but I find it quite interesting.
        YOU_RE_FINALLY_HERE                                                     = 11700,  -- You're finally here, %.
        I_VE_HEARD_OF_YOU_FROM_MY_ASSOCIATES                                    = 11701,  -- I've heard of you from my associates in Norg. As much as I would like to sit and chat with you about your adventures, we must work quickly to find our thief. I have just received a new piece of information and will be setting out shortly to investigate.
        TO_THE_NORTHEAST_OF_HERE_IS_A_PLACE                                     = 11702,  -- To the northeast of here is a place called the Palborough Mines. I've received information on several adventurers sighting a young man wearing a strangely shaped helmet journeying deep into those caves.
        THIS_IS_MORE_THAN_LIKELY_THE_SAME_CHARACTER                             = 11703,  -- This is more than likely the same character that Sanosuke learned of in Jeuno. But why would he head to the Palborough Mines? I'm heading there myself to find out.
        I_HAVE_HEARD_THAT_THE_QUADAV_MADE_THAT                                  = 11704,  -- I have heard that the Quadav made that place into one of their strongholds. I wonder if there could be some connection...
        YOU_MAY_JOURNEY_TO_THE_MINES_WITH_ME                                    = 11705,  -- You may journey to the mines with me if you wish. When you have made your preparations, meet me there. I will be waiting.
        I_IT_S_YOU                                                              = 11706,  -- I-it's you...
        WE_RE_TOO_LATE_HE_S_ALREADY_PASSED                                      = 11707,  -- We're too...late. He's already...passed through the...portal. The seal...on the helmet...won't hold much...longer.
        UNLESS_YOU_WANT_TO_END_UP_LIKE_ME                                       = 11708,  -- Unless you want to end up...like me, don't...touch the burning circle. It's protected...by a powerful curse.
        HURRY_BACK_TO_NORG_AND_TELL_THEM_WHAT                                   = 11709,  -- Hurry...back to Norg and tell...them what's happened. Get something to...break the curse...keep the demon...from escaping...
        ID_11710                                                                = 11710,  -- .........
        HE_HAS_LOST_CONSCIOUSNESS                                               = 11711,  -- He has lost consciousness.
        THE_TIME_HAS_COME_FOR_ME_TO_RISE                                        = 11712,  -- The time has come for me to rise again... I am no longer bound by the chains that annoying Hume forced upon me...
        MANY_A_NIGHT_I_WASTED_AWAY_ROTTING_IN                                   = 11713,  -- Many a night I wasted away, rotting in the darkness of my prison...
        GNYAH_HAH_HAH_BUT_HUMES_ARE_A_FRAIL                                     = 11714,  -- Gnyah-hah-hah! But Humes are a frail species. They grow old and wither away. The one who sent me to my hell is no more...
        NOW_THERE_ARE_NONE_WHO_CAN_STAND_IN                                     = 11715,  -- Now there are none who can stand in my way!
        WHAT_IS_THIS_I_SENSE_SOMEONE_APPROACHING_SOMEONE                        = 11716,  -- What is this? I sense someone approaching... Someone with the same power as that Hume...
        YOU_DID_IT                                                              = 11717,  -- You did it!
        THE_SEAL_WAS_BROKEN_BUT_THANKS_TO_YOU                                   = 11718,  -- The seal was broken, but thanks to you, the demon has been put to rest.
        OUR_ANCESTORS_HAS_BEEN_DAMAGED_BUT_ITS_TATTERED                         = 11719,  -- Our ancestors' % has been damaged, but its tattered appearance is proof of the evil sprit's demise. Take this back to Norg and inform them of your deeds.
        MUCH_OF_THE_CURSED_SEAL_STILL_REMAINS_I                                 = 11720,  -- Much of the cursed seal still remains. I will remain here and attempt to clear the rest of it away. Until we meet again, %!
        THE_HAS_BEEN_BADLY_DAMAGED_YOU_OBTAIN                                   = 11721,  -- The % has been badly damaged... You obtain %.
        THE_YOU_CARRY_HAS_LOST_ITS_EFFECTIVENESS_YOU                            = 11722,  -- The % you carry has lost its effectiveness. You may dispose of it now.
        YOU_VE_CLEARED_SAMURAI_AF_2                                             = 11723,  -- You've cleared Samurai AF 2!
        YOU_DON_T_HAVE                                                          = 11724,  -- You don't have %!
        PRESS_ANY_BUTTON_TO_CONTINUE_PROBABLY_THE_CONFIRMATION                  = 11725,  -- Press any button to continue (probably the confirmation one, though).
        TRICK_OR_TREAT                                                          = 11726,  -- Trick or treat...
        THANK_YOU_AND_NOW_FOR_YOUR_TREAT                                        = 11727,  -- Thank you... And now for your treat...
        HERE_TAKE_THIS                                                          = 11728,  -- Here, take this...
        IF_YOU_PUT_THIS_ON_AND_WALK_AROUND                                      = 11729,  -- If you put this on and walk around, something...unexpected might happen...
        THANK_YOU                                                               = 11730,  -- Thank you...
        IF_TWO_PEOPLE_WITH_THE_SAME_COSTUMES_FORM                               = 11731,  -- If two people with the same costumes form a party and approach a bomb balloon, then...
        PERFECT_TIMING_I_JUST_RECEIVED_A_LETTER_FROM                            = 11732,  -- Perfect timing, %! I just received a letter from Zeid.
        IT_SAYS_DO_NOT_LET_WEREI_S_TECHNIQUE                                    = 11733,  -- It says, Do not let Werei's technique fade. Grant his blade unto those who are worthy.
        HMMM_I_WONDER_IF_HE_MEANS_THE_SWORD                                     = 11734,  -- Hmmm, I wonder if he means the sword Werei forgot to take with him on his journey... Anyway, you look pretty strong. Would you mind trying this out? If you come across anything strange, bring it back to me, and I'll have a look at it.
        WHAT_S_WRONG_YOU_DIDN_T_GO_AND                                          = 11735,  -- What's wrong? You didn't go and lose the sword now, did you?
        WHY_ARE_YOU_HERE_NO_PARTICULAR_REASON_I                                 = 11736,  -- Why are you here? No particular reason. I went and lost the sword... I'm tired of this.
        YOU_KNOW_I_KNEW_YOU_WERE_GOING_TO                                       = 11737,  -- You know, I knew you were going to say that. The sword you lost was delivered to my room earlier today. Here, take it.
        WHAT_YOU_RE_NOT_SERIOUS_ARE_YOU                                         = 11738,  -- What? You're not serious, are you?
        ARE_YOU_SERIOUS_DEAD_SERIOUS_I_WAS_JUST                                 = 11739,  -- Are you serious? Dead serious. I was just bluffing.
        OH_WELL_YOU_CAN_KEEP_THE_SWORD_WEREI                                    = 11740,  -- Oh well, you can keep the sword. Werei left a chest full of these things, and I'm running out of room to store them...
        HM_IT_DOESN_T_LOOK_LIKE_ANYTHING_SPECIAL                                = 11741,  -- Hm? It doesn't look like anything special has happened yet... Maybe you should use it a little bit longer.
        PERFECT_TIMING_I_JUST_GOT_ANOTHER_LETTER_FROM                           = 11742,  -- Perfect timing, %! I just got another letter from Zeid. He said to give you this if there were any changes in the sword.
        HE_ALSO_WANTED_ME_TO_TELL_YOU_THIS                                      = 11743,  -- He also wanted me to tell you this: You will acquire Werei's hidden technique only after you've traveled to the Western Altepa Desert and retrieved the %. Hmph. If this is so important, why couldn't he just come here and give it to you himself?
        YOU_RE_BACK_ALREADY_WELL_LET_S_SEE                                      = 11744,  -- You're back already? Well, let's see what you brought back.
        WAIT_A_MINUTE_THIS_ISN_T_WEREI_S                                        = 11745,  -- Wait a minute... This isn't Werei's technique...
        OH_I_SEE_THAT_S_WHAT_ZEID_WAS                                           = 11746,  -- Oh, I see... That's what Zeid was trying to say.
        I_REMEMBER_WEREI_TELLING_ME_THAT_LONG_AGO                               = 11747,  -- I remember Werei telling me that long ago, the dark knight, Zeid, challenged him to a duel.
        ZEID_WAS_STILL_YOUNG_AND_COULDN_T_MATCH                                 = 11748,  -- Zeid was still young and couldn't match the experience of the elder Werei. However, from his defeat, Zeid was able to devise a powerful new technique.
        IT_WAS_THIS_HEAD_ON_COLLISION_OF_THESE                                  = 11749,  -- It was this head-on collision of these two different styles of battle--no, these two different paths in life--from which this new skill was born.
        WEREI_WANTED_ZEID_TO_REALIZE_THAT_IT_WAS                                = 11750,  -- Werei wanted Zeid to realize that it was not only training, but also the crossing of different paths that made a man strong... Even if those paths were never meant to cross again...
        YOU_KNOW_THE_BATTLES_YOU_HAVE_FOUGHT_HAVE                               = 11751,  -- You know, %. The battles you have fought have probably already taught you some new techniques as well. Use them wisely! Use them wisely!
        YOU_HAVE_LEARNED_THE_WEAPON_SKILL_GROUND_STRIKE                         = 11752,  -- You have learned the weapon skill Ground Strike!
        YOU_HEAR_A_MYSTERIOUS_FLOATING_VOICE_BRING_FORTH                        = 11753,  -- You hear a mysterious, floating voice: Bring forth the %...
        YOU_DO_NOT_MEET_THE_REQUIREMENTS                                        = 11754,  -- You do not meet the requirements.
        THE_TIME_AND_DESTINATION_FOR_YOUR_FORAY_INTO                            = 11755,  -- The time and destination for your foray into Dynamis will be recorded on your %. === Destination: Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] ===
        RECORD_THE_TIME_AND_DESTINATION_PROCEED_NOT_YET                         = 11756,  -- Record the time and destination? Proceed. Not yet. Entering Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia]. Reentering Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia]. Battles in Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia].
        CONNECTING_WITH_SERVER_PLEASE_WAIT                                      = 11757,  -- Connecting with server. Please wait.
        UNABLE_TO_CONNECT                                                       = 11758,  -- Unable to connect.
        YOU_HAVE_NOT_TRADED_THE_NECESSARY_ITEM                                  = 11759,  -- You have not traded the necessary item.
        ANOTHER_GROUP_OF_PLAYER_CHARACTERS_IS_CURRENTLY_OCCUPYING               = 11760,  -- Another group of player characters is currently occupying Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia].
        THE_TIME_AND_DESTINATION_FOR_YOUR_FORAY_INTO_2                          = 11761,  -- The time and destination for your foray into Dynamis has been recorded on your %.
        YOU_DO_NOT_POSSESS_AN_ITEM_THAT_FULFILLS                                = 11762,  -- You do not possess an item that fulfills the requirements.
        YOU_WILL_NOW_BE_WARPED_TO_DYNAMIS                                       = 11763,  -- You will now be warped to Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia].
        READY_TO_WARP_TO_DYNAMIS_READY_READY_SUPPORT                            = 11764,  -- Ready to warp to Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia]? Ready! Ready! (Support jobs unlocked). Ready! (Support jobs restricted). Not yet. Entering Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia]. Reentering Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia]. Battles in Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia].
        YOU_CANNOT_ENTER_DYNAMIS_FOR_VANA_DIEL_TIME                             = 11765,  -- You cannot enter Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] for # [day/days] (Vana'diel time).
        YOU_HEAR_A_MYSTERIOUS_FLOATING_VOICE_THE_GUIDING                        = 11766,  -- You hear a mysterious, floating voice: The guiding aura has not yet faded... Bring forth the %.
        PLAYERS_WHO_HAVE_NOT_REACHED_LEVEL_ARE_PROHIBITED                       = 11767,  -- Players who have not reached level # are prohibited from entering Dynamis.
        PLAYERS_WHO_DO_NOT_POSSESS_ARE_PROHIBITED_FROM                          = 11768,  -- Players who do not possess % are prohibited from entering Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia].
        AND_CANNOT_BE_USED_HERE                                                 = 11769,  -- % and % cannot be used here.
        NOW_THAT_I_HAVE_PASSED_FROM_THE_MORTAL                                  = 11770,  -- %... Now that I have passed from the mortal realm, I have only you to turn to. The time left to me is short.
        THIRTY_YEARS_AGO_I_CAME_INTO_CONTACT_WITH                               = 11771,  -- Thirty years ago, I came into contact with the insidious power of this land, and rose from the grave. However, at the same time, this world laid claim to a part of my soul...
        I_HAVE_BEEN_RELEASED_FROM_THE_HATE_THAT                                 = 11772,  -- I have been released from the hate that consumed me, but the half of my soul that was taken captive all those years ago is calling to me... It has become a towering darkness. A raging hatred, spawned from the depths of my being...
        VERY_SOON_I_WILL_BE_DRAWN_INTO_THAT                                     = 11773,  -- Very soon I will be drawn into that soul. I no longer have the strength to resist. The soul that was divided will become whole once more, and that rage will take on physical form.
        A_NEW_SHADOW_LORD_WILL_BE_BORN_SURELY                                   = 11774,  -- A new Shadow Lord will be born. Surely you have sensed the growing evil? The beastman armies that are imprisoned here are massing for battle. They plan a return to the world of their origin, the realm that exists beneath the light of hope.
        MY_LINK_TO_YOU_WILL_SOON_BE_SEVERED                                     = 11775,  -- My link to you will soon be severed, so listen carefully. Thirty years ago, an expeditionary squad formed from the elite soldiers of each nation was sent to investigate the Northlands. You must have seen their memories when you first laid your hand upon the chunks of magicite.
        SEEK_OUT_THE_MARKINGS_THAT_THE_EXPEDITION_MEMBERS                       = 11776,  -- Seek out the markings that the expedition members left behind. They will aid you in gaining entrance to this world. You must defeat the Shadow Lord before our unification is complete. My hopes go with you, %.
        THERE_IS_AN_UNUSUAL_ARRANGEMENT_OF_BRANCHES_HERE                        = 11777,  -- There is an unusual arrangement of branches here.
        THERE_IS_AN_UNUSUAL_ARRANGEMENT_OF_PEBBLES_HERE                         = 11778,  -- There is an unusual arrangement of pebbles here.
        THE_STRANDS_OF_GRASS_HERE_HAVE_BEEN_TIED                                = 11779,  -- The strands of grass here have been tied together.
        THERE_IS_AN_UNUSUAL_ARRANGEMENT_OF_LEAVES_ON                            = 11780,  -- There is an unusual arrangement of leaves on the ground.
        I_SEE_YOU_HAVE_MET_WITH_RAOGRIMM_HIS                                    = 11781,  -- I see you have met with Raogrimm. His soul is no longer confined to that incarnation of rage, the Shadow Lord, yet the fact remains that he has committed sins beyond redemption.
        IN_SPITE_OF_THOSE_SINS_I_STILL_WISH                                     = 11782,  -- In spite of those sins, I still wish to rescue him from the darkness. I no longer have a mortal body with which to act, and so the most I can do is guide you in my stead.
        YOU_WILL_NEED_THE_A_KEY_THAT_BRIDGES                                    = 11783,  -- You will need the %, a key that bridges the void between Vana'diel and that other world.
        IT_IS_SAID_THAT_THERE_ARE_ITEMS_IN                                      = 11784,  -- It is said that there are items in this world that gain a soul of their own through contact with the thoughts and dreams of other living creatures. The % is one of those items.
        YOU_MUST_LOOK_FOR_THE_GOBLIN_PEDDLERS_THEY                              = 11785,  -- You must look for the Goblin peddlers. They are certain to have knowledge of the %. When you have it safely within your grasp, seek out the markings that we left behind...
        THAT_WORLD_IS_A_LAND_NOW_DRAPED_IN                                      = 11786,  -- That world is a land now draped in the blackest night. We can pass from one world to the other, but without the physical forms lost to us thirty years ago, there is little we can do to intervene.
        RAOGRIMM_IS_THE_ONE_WHO_NO_THE_WORLD                                    = 11787,  -- Raogrimm is the one who... No, the world has been divided into separate realms through the machinations of the new Shadow Lord.
        THE_SHADOW_LORD_RESIDES_IN_THE_XARCABARD_OF                             = 11788,  -- The Shadow Lord resides in the Xarcabard of the other reality. However, I fear you would be marching to your death should you go to confront him... I ask you to first obtain trophies from four of the alternate realms.
        WE_UNDERSTAND_THAT_THERE_IS_LITTLE_TIME_TO                              = 11789,  -- We understand that there is little time to spare. But without a certain degree of power, it will be impossible to traverse the land the Shadow Lord holds in thrall. Show me your strength with the four trophies you bring back.
        THOSE_WHOSE_FATE_IS_LINKED_TO_HIS_WORLD                                 = 11790,  -- Those whose fate is linked to his world will empower the % to guide you...
        I_NEVER_BELIEVED_THAT_MY_INDIFFERENCE_TO_THE                            = 11791,  -- I never believed that my indifference to the state of other nations would cause harm to my beloved San d'Oria...
        AS_PART_OF_MY_PENANCE_I_WILL_INFUSE                                     = 11792,  -- As part of my penance, I will infuse the % with what guidance I can.
        I_BETRAYED_HIM_AND_NOW_I_AM_NEEDED                                      = 11793,  -- I betrayed him... And now I am needed, the one who cut down poor Cornelia. The man cursed with the brand of traitor...
        SURE_I_GOT_EVERYTHING_I_WANTED_BUT_WHAT                                 = 11794,  -- Sure, I got everything I wanted, but what was left to me in the end? For one rash action, all I gained was an empty title and irreconcilable guilt...
        I_DOUBT_YOU_LL_LISTEN_TO_THE_WORDS                                      = 11795,  -- I doubt you'll listen to the words of a traitor, but please, help free him from the bonds of his eternal night...
        OUR_EXPEDITION_WAS_SUPPOSED_TO_HAVE_BEEN_AN                             = 11796,  -- Our expedition was supposed to have been an allied effortaru, but not one of us was interested in the fate of the other nations. In our hasty-waste to outdo each other, we failed to see to the heart of the mattaru.
        OUR_ATTITUDES_LED_TO_THE_DEATH_OF_TWO                                   = 11797,  -- Our attitudes led to the death of two of our members, and precipitated the birth of the Shadow Lord... This sin does not belong on Raogrimm's shoulders alone. We all mustaru atone for our actions.
        PLEASE_HELP_HIM_HELP_RAOGRIMM_ESCAPE_FROM_HIS                           = 11798,  -- Please help him. Help Raogrimm escape from his horrid-worrid darkness, forever this time.
        HUMES_AND_GALKA_HAVE_NEVER_BEEN_THE_BEST                                = 11799,  -- Humes and Galka have never been the best of friends. I used to think that was just the way it was, and always would be.
        I_FIGURED_I_D_BE_CAUSING_MYSELF_GRRRIEF                                 = 11800,  -- I figured I'd be causing myself grrrief if I stuck my whiskers into other nations' problems. My next catnap was all that mattered to me in those days. Ignorrrance is bliss, as they say.
        RESPONSIBILITY_FOR_RAOGRIMM_S_TRRRANSFORMATION_LIES_WITH_ALL            = 11801,  -- Responsibility for Raogrimm's trrransformation lies with all of us who traveled with him on that expedition. By sharing the blame for the crimes he committed as the Shadow Lord, we can finally call ourselves his trrrue companions.
        LET_ME_HELP_YOU_ON_YOUR_PATH_MAY                                        = 11802,  -- Let me help you on your path. May guiding light fill this %! Raogrimm's fate is in your hands.
        THERE_IS_A_BROKEN_BRANCH_THRUST_INTO_THE                                = 11803,  -- There is a broken branch thrust into the ground here.
        THERE_IS_A_SYMBOL_CARVED_INTO_THE_ROCK                                  = 11804,  -- There is a symbol carved into the rock here.
        I_HAVE_BEEN_WAITING_FOR_YOU                                             = 11805,  -- I have been waiting for you.
        DO_YOU_REMEMBER_THE_LAST_WORDS_RAOGRIMM_SPOKE                           = 11806,  -- Do you remember the last words Raogrimm spoke to you? "The link will soon be severed"... Do you understand the significance of these words?
        WHEN_THE_SOUL_THAT_WAS_DIVIDED_IS_WHOLE                                 = 11807,  -- When the soul that was divided is whole once again, towering rage will take on physical form... Yes, a new Shadow Lord will be born. Even I will no longer hear his voice.
        EVEN_NOW_I_CAN_BARELY_FEEL_THE_EMANATIONS                               = 11808,  -- Even now, I can barely feel the emanations of Raogrimm's faltering spirit. When those emanations fade completely, he will be...
        THE_XARCABARD_OF_THAT_OTHER_REALM_IS_SHROUDED                           = 11809,  -- The Xarcabard of that other realm is shrouded in a vast darkness, preventing contact from the outside. Even those of us without material bodies are unable to penetrate that mist of eternal night.
        UNTIL_THAT_MIST_CLEARS_I_CANNOT_GUIDE_YOU                               = 11810,  -- Until that mist clears, I cannot guide you to Xarcabard. The next place you must venture is the twin of Vana'diel's Beaucedine. There you will find the last trophy to complete the set of keys we need.
        YOU_MUST_OBTAIN_THE_LAST_TROPHY_ALL_FIVE                                = 11811,  -- You must obtain the last trophy. All five trophies combined with our power will create a synergistic force, allowing us to part the shroud for a few precious moments. It will open a path between worlds.
        TAKE_CARE_MY_BRAVE_ADVENTURER_MAY_THE_BLESSINGS                         = 11812,  -- Take care, my brave adventurer. May the blessings of Altana guide and protect you...
        EVEN_AFTER_THE_BLACKEST_NIGHT_THE_GOLDEN_SUN                            = 11813,  -- Even after the blackest night, the golden sun always rises to begin a new morning. This troubled land will soon have its dawn...of that I am certain.
        I_NEVER_THOUGHT_TO_WALK_THIS_LAND_AGAIN                                 = 11814,  -- I never thought to walk this land again, not even in death. Is this what they call karma...?
        THIS_LAND_HAS_BORNE_THE_WEIGHT_OF_MY                                    = 11815,  -- This land has borne the weight of my sins. I will not beg for forgiveness, but accept my responsibility...
        SO_THIS_IS_THE_REASON_FOR_THAT_UNSPEAKABLE                              = 11816,  -- So this is the reason for that unspeakable terror I feltaru here when I was still alive. It's possible that the other realm has existed for much longer than anyone ever dreamed... Keep your wits aboutaru you, %.
        I_M_NOT_RRREALLY_FOND_OF_TOUCHING_PLATITUDES                            = 11817,  -- I'm not rrreally fond of touching platitudes. Snap Raogrimm to his senses with a big ol' smack to the head for me.
        IT_IS_TIME_PUT_AN_END_TO_THIS                                           = 11818,  -- It is time! Put an end to this thirty-year nightmare, %. %! Show us the path to Xarcabard!
        DEATH_DOES_NOT_EXIST_IN_THAT_REALM_YOU                                  = 11819,  -- Death does not exist in that realm. You might call it a prison of souls.
        EVEN_THOSE_WHO_FALL_IN_BATTLE_WILL_RISE                                 = 11820,  -- Even those who fall in battle will rise again after a time as if nothing had happened. Like a flame returning to a candle whose light has been extinguished...
        IT_IS_AN_ENDLESS_SUCCESSION_OF_LIFE_AND                                 = 11821,  -- It is an endless succession of life and death. How many times has that cycle repeated itself in that damned abode?
        THERE_IS_ONE_THING_THAT_BOTHERS_ME_WHATEVER                             = 11822,  -- There is one thing that bothers me. Whatever happened to the original wielders of the weapons and armor that the beastmen there now possess? If the statues in the shape of Orcs and such were once actual beastmen, then...? But I get carried away with my musings.
        PLEASE_PAY_NO_MIND_TO_MY_RAMBLINGS_YOU                                  = 11823,  -- Please pay no mind to my ramblings. You have secured the %. An incredible feat. It proves the strength of your conviction, and is one of the keys you will need to enter Xarcabard.
        YOU_WILL_NEED_FOUR_SUCH_TROPHIES_ONCE_YOU                               = 11824,  -- You will need four such trophies. Once you have them within your grasp, make your way to Beaucedine Glacier in the Northlands. Cornelia awaits you there.
        I_DON_T_KNOW_ABOUT_THE_OTHER_FOUR                                       = 11825,  -- I don't know about the other four, but I can't hear his voice anymore...
        IS_THIS_ANOTHER_BRAND_I_MUST_BEAR_FOR                                   = 11826,  -- Is this another brand I must bear for my treachery? I must truly be hated if that's the case.
        IT_IS_SOMETHING_I_WOULD_WISH_FOR_AT                                     = 11827,  -- It is something I would wish for at the moment, however. I pray this silence is just a continuation of our incompatible personalities. If not, then it means his pronouncement has become reality...
        THIS_IS_MORE_THAN_JUST_A_TESTAMENT_TO                                   = 11828,  -- %. This is more than just a testament to your strength. It is one of the keys that will lead you to Xarcabard, along with the trophies of the other realms.
        WHEN_YOU_HAVE_ALL_FOUR_TROPHIES_TRAVEL_TO                               = 11829,  -- When you have all four trophies, travel to Beaucedine Glacier in the Northlands. You will find Cornelia waiting for you there. That is all the wisdom I have left to give you.
        WHAT_IS_THE_TRUE_NATURE_OF_THAT_OTHER                                   = 11830,  -- What is the true nature of that other world? I can only explain it as a place that lies beyond the limitarus of our knowledge. But I'm sure I've feltaru that aura somewhere before...
        THAT_S_IT_THAT_PROTOCRYSTAL_I_CAME_ACROSS                               = 11831,  -- That's it. That protocrystal I came across when I was doing research in Elshimo. The magical emanations coming from the crystal gave me a similar impression. An avatar? No, that can'taru be...
        OH_OH_I_M_TERRIBLY_WERRIBLY_SORRY_I                                     = 11832,  -- Oh! Oh, I'm terribly-werribly sorry! I appear to have driftarued into my old habits.
        NOW_THIS_IS_BOTH_A_SYMBOL_OF_YOUR                                       = 11833,  -- Now, %. This % is both a symbol of your fortitude, and one of the keys that will help you gain access to Xarcabard. The trophies from the other three realms carry the same importance.
        GATHER_ALL_FOUR_TROPHIES_AND_HURRY_YOURSELF_ON                          = 11834,  -- Gather all four trophies and hurry yourself on to Beaucedine Glacier. Cornelia will be waiting for you when you get there. But be wary, %. The blackness enveloping that world grows ever deeper, ever darker...
        THE_BEASTMEN_OF_THAT_WORLD_CARRY_THE_SPOILS                             = 11835,  -- The beastmen of that world carry the spoils of prrrevious battles. Equipment that you or I would use.
        I_M_NOT_ABLE_TO_TOUCH_THEM_IN                                           = 11836,  -- I'm not able to touch them in my prrresent form, but I feel something about those weapons and armor...something extrrraordinary.
        WAIT_WAIT_WAIT_I_DON_T_MEAN_THAT                                        = 11837,  -- Wait, wait, wait! I don't mean that they're currrsed or anything like that! It's something more like, um, not ominous, but... How can I explain it?
        ANYWAY_THEY_RE_NOT_EVIL_JUST_YOU_KNOW                                   = 11838,  -- Anyway! They're not evil, just...you know? Different from other normal swords and things. Being all ghostlike and stuff, you can feel things like that.
        BUT_ENOUGH_OF_THAT_KINDA_TALK_CONGRRRATULATIONS_ARE                     = 11839,  -- But enough of that kinda talk--congrrratulations are in order! You've got your paws on the %! It shows you've got the goods in the hero department, and it will also help you get into Xarcabard.
        BUT_FIRST_YOU_VE_GOT_TO_COLLECT_THE                                     = 11840,  -- But first you've got to collect the other three trophies and then hightail it to snowy Beaucedine Glacier. Cornelia should be up there waiting for you.
        AND_THE_FOUR_TROPHIES_THESE_ARTIFACTS_HAVE_LONG                         = 11841,  -- % and the four trophies. These artifacts have long been lost to that other world. The Hydra Corps was a unit formed after our expedition to the Northlands.
        IT_MUST_HAVE_BEEN_IN_THE_TIME_OF                                        = 11842,  -- It must have been in the time of the Great War... Nobody knows how the Hydra artifacts came to be there, but those five trophies will open the path for you.
        EACH_OF_THESE_ITEMS_HOLDS_A_MEASURE_OF                                  = 11843,  -- Each of these items holds a measure of power. However, the strength of a single artifact is limited.
        THE_AND_THE_COMBINING_THESE_SEPARATE_ENTITIES_CREATED                   = 11844,  -- The % and the %. Combining these separate entities created a bridge from Vana'diel to the other realms. Xarcabard, I'm afraid, is another matter entirely...
        UNLESS_THE_SHROUD_OF_DARKNESS_IS_LIFTED_THAT                            = 11845,  -- Unless the shroud of darkness is lifted, that power alone will not be enough to open the way. However, the five trophies resonate with another artifact that lies within his land. If we can join our strength to theirs...
        LET_US_MAKE_HASTE_TO_THE_LAND_WHERE                                     = 11846,  -- Let us make haste to the land where this all began. To Xarcabard...
        IS_IT_OVER                                                              = 11847,  -- Is it over...?
        NO_THE_RAGE_HAS_MERELY_BEEN_DISPERSED                                   = 11848,  -- No, the rage has merely been dispersed.
        AS_LONG_AS_I_EXIST_HE_WILL_NEVER                                        = 11849,  -- As long as I exist, he will never truly die...
        OR_PERHAPS_AN_ETERNAL_SOUL_IS_SOMETHING_BEYOND                          = 11850,  -- Or perhaps an eternal soul is something beyond the concept of death?
        YOU_HAVE_ACHIEVED_AN_INCREDIBLE_FEAT_THE_UNIFICATION                    = 11851,  -- %... You have achieved an incredible feat--the unification of the Shadow Lord has been prevented. I have not the words to express my gratitude.
        THE_POWER_OF_THE_CRYSTAL_HAS_FADED_BUT                                  = 11852,  -- The power of the crystal has faded, but I will be drawn into that towering rage no more. I have heard the voice of the one who holds sway over this realm...
        THE_ONE_WHO_HOLDS_SWAY                                                  = 11853,  -- The one who holds sway...?
        YES_FROM_THE_CENTER_OF_INFINITE_DARKNESS_I                              = 11854,  -- Yes. From the center of infinite darkness. I was in a place beyond comprehension when those words reached into my mind...
        YOU_WHO_HAVE_TOUCHED_THE_CRYSTAL_THE_ONE                                = 11855,  -- You who have touched the crystal, the one who holds immortal power within a mortal shell. The rage that has arisen from your twisted core will devour my world.
        IT_WAS_AN_ERROR_IN_JUDGMENT_TO_SHELTER                                  = 11856,  -- It was an error in judgment to shelter you... The order of my realm has been disrupted.
        I_GIVE_TO_YOU_A_DUTY_YOU_WILL                                           = 11857,  -- I give to you a duty... You will stand vigil until an age without hatred has dawned.
        NO_MATTER_WHAT_TERRIBLE_POWER_YOU_MIGHT_WIELD                           = 11858,  -- No matter what terrible power you might wield, there is no escape from Dynamis for an incomplete soul. No return to the land of blessed light...
        WHAT_MANNER_OF_BEING_WAS_THIS_WHO_SPOKE                                 = 11859,  -- What manner of being was this who spoke from a pit of blackness? As this question gnawed at my mind, the voice grew quiet, leaving me in unanswered silence.
        OF_ONE_THING_I_WAS_CERTAIN_THIS_VOICE                                   = 11860,  -- Of one thing I was certain. This voice belonged to the ruler of Dynamis.
        A_FLOW_OF_ENERGY_EXISTS_IN_VANA_DIEL                                    = 11861,  -- A flow of energy exists in Vana'diel that has escaped the notice of those who dwell there.
        THIRTY_YEARS_PAST_MY_CONTACT_WITH_THE_CRYSTAL                           = 11862,  -- Thirty years past, my contact with the crystal caused an accelerated change in this flow. It was as if it had leapt forward, rushing along a deliberate course.
        NOBODY_KNOWS_WHAT_LIES_AT_THE_END_OF                                    = 11863,  -- Nobody knows what lies at the end of this journey. Perhaps it will reveal the true nature of Vana'diel.
        YOU_MAY_BE_THE_ONE_TO_WITNESS_THIS                                      = 11864,  -- %, you may be the one to witness this truth.
        THE_POWER_STORED_IN_THE_WILL_SOON_BE                                    = 11865,  -- The power stored in the % will soon be drained. And I must remain in this world in my role of observer.
        DO_NOT_FORGET_WHO_YOU_ARE_I_BID                                         = 11866,  -- Do not forget who you are, %. I bid farewell to a most heroic adventurer.
        MY_OLD_COMPANIONS                                                       = 11867,  -- My old companions...?
        THIS_DUTY_IS_TOO_MUCH_FOR_JUST_ONE                                      = 11868,  -- This duty is too much for just one to bear. If you will have me, I will stand at your side until an age without hatred has arrived. It pains me to see the depths to which my country has fallen.
        THAT_IS_MY_ONLY_REASON_FOR_STAYING_DO                                   = 11869,  -- That is my only reason for staying. Do not misunderstand my motivations.
        BLESSED_LIGHT_AND_THE_RULER_OF_DYNAMIS_I                                = 11870,  -- Blessed light and the ruler of Dynamis? I do believe you've rekindled my long-forgotten sense of adventure.
        ONCE_I_VE_GOTTEN_ALL_FIREDY_UP_EVEN                                     = 11871,  -- Once I've gotten all firedy-up, even you can'taru keep me back, Raogrimm. I'm sure my incomparable research skills will be of use in your task.
        C_MON_LET_S_SEE_A_LITTLE_EXCITEMENT                                     = 11872,  -- C'mon, let's see a little excitement! This is our expedition's thirty-year rrreunion.
        IT_S_NOT_THE_NORTHLANDS_THIS_TIME_NONE                                  = 11873,  -- It's not the Northlands this time. None of us are going to grow old and die, so who else would you want with you on a task as long as this one?
        I_M_NOT_GONNA_BACK_DOWN_NO_MATTERRR                                     = 11874,  -- I'm not gonna back down, no matterrr how much you complain. Better just give in and accept the fact that you're stuck with me.
        I_THOUGHT_THIS_WOULD_BE_THE_END_OF                                      = 11875,  -- I thought this would be the end of you for sure... Hmph. You're just as thick-skinned as you used to be.
        WHAT_NO_WORDS_FOR_AN_OLD_FRIEND_THINKING                                = 11876,  -- What, no words for an old friend? Thinking about testing your theory on whether or not a soul can be killed?
        I_BETRAYED_YOU_I_EXTINGUISHED_THE_LIGHT_OF                              = 11877,  -- I betrayed you! I extinguished the light of your precious Cornelia! The man responsible for this entire nightmare stands right before you!
        EVERYTHING_BEGAN_THIRTY_YEARS_AGO_AND_THERE_WERE                        = 11878,  -- Everything began thirty years ago. And there were things that came to an end... Even though I was a prisoner of uncontrollable rage, the fact remains that I took the lives of my companions with my own hands.
        AND_YET_MY_OLD_COMPANIONS_YOU_ARE_THE                                   = 11879,  -- And yet, my old companions, you are the ones who have saved me from falling into that pit of hatred a second time.
        I_HAVE_WORDS_OF_GRATITUDE_BUT_DO_NOT                                    = 11880,  -- I have words of gratitude, but do not stand in a position to blame anyone for their actions. No matter who that person may be.
        RAOGRIMM                                                                = 11881,  -- Raogrimm...
        ARE_YOU_SURE_YOU_WANT_TO_DO_THIS                                        = 11882,  -- Are you sure you want to do this? This duty will continue until hatred has faded from the land. As long as my divided soul remains, there may never be an end to that rage...
        RAOGRIMM_THERE_IS_NO_NEED_TO_SUFFER_ALONE                               = 11883,  -- Raogrimm. There is no need to suffer alone anymore. Our presence here should answer your question.
        THERE_ARE_CRIMES_THAT_MUST_BE_ATONED_FOR                                = 11884,  -- There are crimes that must be atoned for. And if that means staying on after death and watching over this world, then we who were your companions will share the burden along with you.
        UNTIL_THE_DAWN_OF_AN_AGE_WITHOUT_HATRED                                 = 11885,  -- Until the dawn of an age without hatred... No, as long as this world continues to be, I will remain by your side.
        CORNELIA                                                                = 11886,  -- Cornelia...
        FBNJ_S_V_S_V                                                            = 11887,  -- *#`FbNj%[ -s [v -s[v
        UJO_HN_ACXG                                                             = 11888,  -- UJo[hN#ACxg
        THERE_IS_A_STRANGE_SYMBOL_DRAWN_HERE_A                                  = 11889,  -- There is a strange symbol drawn here. A haunting chill sweeps through you as you gaze upon it...
        YOU_HEAR_A_MYSTERIOUS_FLOATING_VOICE_PRESENT_THE                        = 11890,  -- You hear a mysterious, floating voice: Present the %...if you wish to pass into...my dream.
        YOU_HEAR_A_MYSTERIOUS_FLOATING_VOICE_THE_SANDS                          = 11891,  -- You hear a mysterious, floating voice: The sands of time yet fall... Present the...%.
        I_AM_THE_RULER_OF_DYNAMIS                                               = 11892,  -- I am the ruler of Dynamis.
        ARE_YOU_LOST_OR_ARE_YOU_HERE_BY                                         = 11893,  -- Are you lost? Or are you here by your own reckless designs? Either way, this is not your dream.
        THE_DREAMER_OF_THIS_REALM_IS_A_SEPARATE                                 = 11894,  -- The dreamer of this realm is a separate entity than he who dreamt of that wasteland of malice, Xarcabard.
        WHO_WOULD_DARE_BRING_A_NEW_DREAM_INTO                                   = 11895,  -- Who would dare bring a new dream into my world of Dynamis?
        I_DIVIDED_MY_FORM_IN_ORDER_TO_FIND                                      = 11896,  -- I divided my form in order to find the answer, but my counterpart has yet to return to me.
        WHILE_WANDERING_THROUGH_THIS_REALM_YOU_MAY_COME                         = 11897,  -- While wandering through this realm, you may come across another semblance of myself.
        THE_MEMORY_OF_OUR_ENCOUNTER_WILL_BECOME_A                               = 11898,  -- The memory of our encounter will become a guide to my shadow as it wanders this dream.
        SEARCH_FOR_MY_COUNTERPART_AND_UNITE_THIS_REALM                          = 11899,  -- Search for my counterpart, and unite this realm with your own dream.
        A_NIGHTMARE_CURSES_THIS_LAND_YET_AGAIN                                  = 11900,  -- A nightmare curses this land yet again.
        TAKE_HEED_DREAM_TRAVELER                                                = 11901,  -- Take heed, dream traveler.
        I_HAVE_BEEN_WATCHING_YOUR_DREAM                                         = 11902,  -- I have been watching your dream.
        BUT_YOU_CANNOT_GRASP_THE_IDENTITY_OF_THIS                               = 11903,  -- But you cannot grasp the identity of this realm's dreamer from there. This land will continue to devour its way into Dynamis.
        YOU_MUST_FIND_MY_COUNTERPART_AND_CRUSH_THE                              = 11904,  -- You must find my counterpart and crush the dreamer of this realm.
        I_SEE_THAT_YOU_HAVE_GATHERED_THREE_SLIVERS                              = 11905,  -- I see that you have gathered three slivers of black crystal...
        THE_EMPTINESS_IS_SEALED_INSIDE_OF_THEM_THOSE                            = 11906,  -- The Emptiness is sealed inside of them. Those are no mere fragments.
        THOSE_PIECES_OF_CRYSTAL_HAVE_LED_YOU_TO                                 = 11907,  -- Those pieces of crystal have led you to this place... The source of this nightmare is near. I can feel the dreamer's presence.
        THE_ENTRANCE_TO_THE_DREAM_HAS_ALREADY_BEEN                              = 11908,  -- The entrance to the dream has already been opened. Find and destroy the source if you wish to protect my realm.
        I_AM_A_UNIQUE_ENTITY                                                    = 11909,  -- I am...a unique entity...
        WE_ARE_COMPRISED_OF_ALL_ENTITIES                                        = 11910,  -- We are...comprised of all entities...
        INTERMINGLING_WITH_ONE_ANOTHER_DIVIDING_AMONG_EACH_OTHER                = 11911,  -- Intermingling with one another...dividing among each other...
        AND_DEVOURING_ONE_ANOTHER                                               = 11912,  -- And devouring one another...
        THE_SHADOW_THAT_YOU_DEFEATED_HAD_BEEN_CONSUMED                          = 11913,  -- The shadow that you defeated had been consumed by the dreamer of this realm.
        IT_SEEMS_THAT_THIS_NIGHTMARE_WAS_DREAMT_INTO                            = 11914,  -- It seems that this nightmare was dreamt into existence by beings who have come into contact with the Emptiness.
        IT_SEEMS_THAT_THIS_NIGHTMARE_WAS_DREAMT_INTO_2                          = 11915,  -- It seems that this nightmare was dreamt into existence by beings who came into contact with the Emptiness.
        COULD_IT_HAVE_BEEN_THAT_GIRL_WHEN_I                                     = 11916,  -- Could it have been that girl...? When I next see her, she will pay dearly.
        COULD_IT_HAVE_BEEN_THAT_GIRL_NO_THERE                                   = 11917,  -- Could it have been that girl...? No, there was one more, transformed after death...
        HER_MALICE_WILL_NOT_PERISH_AS_LONG_AS                                   = 11918,  -- Her malice will not perish as long as this dream continues, using my shadows to revive countless times.
        YOU_MUST_CONFRONT_THE_NIGHTMARE_AND_CONTINUE_TO                         = 11919,  -- You must confront the nightmare and continue to fight them to keep this realm from spreading.
        THE_DREAMER_IS_NOT_THE_GIRL_WHO_ONCE                                    = 11920,  -- The dreamer is not the girl who once harbored the Emptiness... Could it have been transferred to another girl...?
        YOU_KNOW_THIS_GIRL_WELL_I_COULD_TAKE                                    = 11921,  -- You know this girl well. I could take care of her easily, but if you wish me to spare her, then you will lend me your power.
        TRADE_THE_TO_THE_HIEROGLYPHICS_FOUND_IN_EACH                            = 11922,  -- Trade the % to the Hieroglyphics found in each area. The % will be transformed into %.
        FROM_THAT_POINT_ON_ONE_OF_THE_AREAS                                     = 11923,  -- From that point on, one of the areas of Dynamis will be reserved by the bearer of the %. The destination and time to be spent in Dynamis will be recorded in the help text of the %.
        BY_DEFEATING_CERTAIN_ENEMIES_A_GROUP_CAN_EXTEND                         = 11924,  -- By defeating certain enemies, a group can extend the amount of time they are allowed in Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia]. Any time extensions will be reflected in the %'s help text.
        USING_THE_CREATES_A_COPY_BY_HANDING_THESE                               = 11925,  -- Using the % creates a copy. By handing these copies out to other characters, it is possible to enter Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] in large groups.
        THE_NUMBER_OF_CHARACTERS_THAT_CAN_ENTER_DYNAMIS                         = 11926,  -- The number of characters that can enter Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] at one time is limited to # people.
        THE_CAN_BE_DUPLICATED_FURTHER_BY_THOSE_WHO                              = 11927,  -- The % can be duplicated further by those who have received a copy, essentially allowing for an unlimited number of % to be made. However, the moment the maximum allowable number of players have entered Dynamis, all extra hourglasses will become void. Please take this into consideration when deciding to whom, and how many, copies are to be handed out.
        TO_WARP_TO_DYNAMIS_TRADE_THE_TO_THE                                     = 11928,  -- To warp to Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia], Trade the % to the Hieroglyphics where you originally received it.
        PLEASE_NOTE_THAT_IT_IS_NOT_POSSIBLE_TO                                  = 11929,  -- Please note that it is not possible to enter Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] without %, even if you trade the required %.
        IN_ADDITION_ONLY_PLAYERS_ABOVE_LEVEL_64_CAN                             = 11930,  -- In addition, only players above level 64 can travel to the Shrouded Land.
        ENSURING_THAT_YOU_HAVE_IN_YOUR_POSSESSION_SEEK                          = 11931,  -- Ensuring that you have % in your possession, seek out the Trail Markings or Hieroglyphics found in each area.
        EXAMINE_THEM_AND_YOU_WILL_BE_GRANTED_ENTRANCE                           = 11932,  -- Examine them and you will be granted entrance to the corresponding Dynamis area.
        DYNAMIS_WILL_NOT_BE_RESERVED_TO_ANYONE_IT                               = 11933,  -- Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] will not be reserved to anyone. It will be accessible to any and all who meet the entry requirements.
        YOUR_STAY_IN_DYNAMIS_WILL_BE_SUBJECT_TO                                 = 11934,  -- Your stay in Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] will be subject to a time restriction. Parties will automatically be expelled from the area when this time elapses.
        PARTIES_AND_ALLIANCES_CAN_EXTEND_THEIR_DURATION_OF                      = 11935,  -- Parties and alliances can extend their duration of stay by defeating certain enemies.
        PLEASE_NOTE_THAT_IT_IS_NOT_POSSIBLE_TO_2                                = 11936,  -- Please note that it is not possible to enter Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] without %, even if you trade the required %.
        REMEMBER_THAT_ONLY_PLAYERS_LEVEL_65_OR_ABOVE                            = 11937,  -- Remember that only players level 65 or above can travel to the Shrouded Land.
        FURTHERMORE_IT_IS_NOT_POSSIBLE_TO_RESERVE_DYNAMIS                       = 11938,  -- Furthermore, it is not possible to reserve Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] using % or %.
        EVEN_IF_YOU_LEAVE_DYNAMIS_THROUGH_MAGIC_OR                              = 11939,  -- Even if you leave Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] through magic or being KO'd, you can reenter the same area without restriction as long as it is within the designated time of the %.
        HOWEVER_YOU_WILL_BE_IN_A_WEAKENED_STATE                                 = 11940,  -- However, you will be in a weakened state for some time upon returning to Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia].
        THIS_WEAKENED_STATE_WILL_LAST_FOR_LONGER_THAN                           = 11941,  -- This weakened state will last for longer than the usual period experienced after being raised from KO status.
        UPON_ENTERING_DYNAMIS_YOU_WILL_BE_UNABLE_TO                             = 11942,  -- Upon entering Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia], you will be unable to reenter using a different % for # [day/days] (Earth time).
        IN_ADDITION_TO_DYNAMIS_THIS_RESTRICTION_WILL_ALSO                       = 11943,  -- In addition to Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia], this restriction will also apply to the following Dynamis areas:
        DYNAMIS_DYNAMIS_DYNAMIS                                                 = 11944,  -- Dynamis - [Dummy/Dummy/Dummy/Dummy/Dummy/Dummy/Dummy/Buburimu/Valkurm/Valkurm/Valkurm]. Dynamis - [Dummy/Dummy/Dummy/Dummy/Dummy/Dummy/Dummy/Qufim/Qufim/Buburimu/Buburimu]. Dynamis - [Dummy/Dummy/Dummy/Dummy/Dummy/Dummy/Dummy/Tavnazia/Tavnazia/Tavnazia/Qufim.]
