        THESE_INITIAL_EGGS_ARE_REALLY_EGG_SPENSIVE_KUPO                         = 11968,  -- These initial eggs are really egg-spensive, kupo! If you want one I'm going to need a little more incentive. No egg-ceptions!
        EGGS_ACTLY_WHAT_I_WANTED_HERE_S_YOUR                                    = 11969,  -- Eggs-actly what I wanted! Here's your reward, kupo!
        KU_KUPO_SUCH_AN_EGG_STRAVAGANT_ITEM_FOR                                 = 11970,  -- Ku-kupo! Such an egg-stravagant item, for little old me? Here's a whole basketful of initial eggs for you, kupo!
