        CHOCOBOS_LIKE_TO_GIVE_THINGS_THEY_VE_PICKED_2                           = 14112,  -- Chocobos like to give things they've picked up to their parents...which would be you in this case.
        IT_SEEMS_YOUR_CHOCOBO_FOUND_THIS_ON_ONE                                 = 14113,  -- It seems your chocobo found this on one of your walks.
