        YOU_VE_GOT_A_CERTAIN_WAY_ABOUT_YOU                                      = 14125,  -- You've got a certain way about you... Could it be...?
        SHOW_HIM_LELEROON_S_LETTER_YES_NO_WAY                                   = 14126,  -- Show him Leleroon's letter? Yes. No way.
        A_LETTER_FROM_LELEROON_THAT_S_GREAT_NEWS                                = 14127,  -- A letter from Leleroon? That's great news!
        SNIFF_SNIFF                                                             = 14128,  -- <Sniff sniff>...
        THAT_S_THE_SCENT_OF_THE_QIQIRN_ALL                                      = 14129,  -- That's the scent of the Qiqirn, all right.
        SORRY_I_M_JUST_AMAZED_BY_YOUR_POWERS                                    = 14130,  -- Sorry... I'm just amazed by your powers of observation... You saw right through my disguise even in this giant town!
        I_M_WATZAHL_THE_MOST_SKILLED_CRAFTSMAN_THAT                             = 14131,  -- I'm Watzahl, the most skilled craftsman that ever sailed on the Black Cradle.
        THERE_ARE_SO_MANY_MATERIALS_FOR_MY_CRAFT                                = 14132,  -- There are so many materials for my craft in the Middle Lands that I just can't find elsewhere... All the excitement's kept me here far longer than it should.
        BUT_I_DO_MISS_ARADJIAH_THE_SEAGULL_PHRATRIE                             = 14133,  -- But I do miss Aradjiah... The Seagull Phratrie's been pretty active lately, haven't they?
        HEH_HEH_OF_COURSE_I_KNOW_WHAT_S                                         = 14134,  -- Heh heh, of course I know what's going on in the Near East. You would be wise not to underestimate the power of the corsair information network.
        WELL_I_MIGHT_AS_WELL_TAKE_THIS_OPPORTUNITY                              = 14135,  -- Well, I might as well take this opportunity and head back to see how everyone's doing in Aradjiah!
        I_D_LIKE_TO_SEE_LELEROON_AGAIN_TOO                                      = 14136,  -- (I'd like to see Leleroon again, too.)
        AH_I_ALMOST_FORGOT_YOU_WANTED_TO_TALK                                   = 14137,  -- ...Ah, I almost forgot. You wanted to talk to me about something, didn't you?
        JUDGING_BY_THE_LOOK_OF_YA_YOU_PROBABLY                                  = 14138,  -- Judging by the look of ya, you probably want %, don't you?
        HEHEH_I_KNEW_IT_NEVER_UNDERESTIMATE_THE_CORSAIRS                        = 14139,  -- Heheh, I knew it. Never underestimate the corsairs' powers of observation.
        I_LL_NEED_AND                                                           = 14140,  -- I'll need %, %, %, and %...
        WITH_THEM_THE_LEGENDARY_CORSAIR_ARMOR_CAN_BE                            = 14141,  -- With them, the legendary corsair armor can be yours.
        BRING_EVERYTHING_TO_ME_AND_I_LL_SHOW                                    = 14142,  -- Bring everything to me, and I'll show you some real craftsmanship.
        AND                                                                     = 14143,  -- %, %, %, and %
        DON_T_FORGET                                                            = 14144,  -- Don't forget!
        NOW_HURRY_UP_AND_GET_THE_GOODS                                          = 14145,  -- Now hurry up and get the goods.
        I_LL_NEED_SOME_FOR_MY_SHARE                                             = 14146,  -- I'll need some % for my share...
        YOU_VE_HEARD_OF_THEM_BEFORE_RIGHT_BRING                                 = 14147,  -- You've heard of them before, right? Bring me #, and we have a deal.
        GET_THEM_HERE_NO_MATTER_WHAT_IT_TAKES                                   = 14148,  -- Get them here no matter what it takes, got it?
        DON_T_FORGET_2                                                          = 14149,  -- Don't forget--# !
        GREAT_NOW_JUST_LEAVE_EVERYTHING_TO_ME                                   = 14150,  -- Great. Now just leave everything to me.
        COME_BACK_LATER_AND_I_LL_HAVE_SOME                                      = 14151,  -- Come back later, and I'll have some shiny new armor just waiting for you to try on.
        IMPATIENT_AREN_T_WE_GO_PLAY_DICE_WITH                                   = 14152,  -- Impatient, aren't we? Go play dice with some kids or something, and I should finish in no time.
        YOUR_ORDER_IS_READY_HERE_YA_GO_THEY                                     = 14153,  -- Your order is ready. Here ya go... They're yours now.
        I_MADE_THESE_ESPECIALLY_FOR_YOU_SO_USE                                  = 14154,  -- I made these especially for you, so use them wisely, all right? I guarantee their practicality.
        WELL_I_BETTER_HEAD_FOR_ARADJIAH_NOW                                     = 14155,  -- Well, I better head for Aradjiah now...
        SEE_YOU_ON_ARRAPAGO_REEF_WHEN_YOU_RE                                    = 14156,  -- See you on Arrapago Reef when you're ready!
        THE_DOOR_IS_FIRMLY_SHUT                                                 = 14157,  -- The door is firmly shut...
        AHHH_THE_PAIN_THE_SHEER_AGONY_HERE_I                                    = 14158,  -- Ahhh, the pain! The sheer agony! Here I stand on the verge of the single greatest breakthrough in the long and storied history of the alchemical arts, and--the Twilight God take me--I lack for the key ingredient necessary to consummate my life's work! If only--
        WAIT_COULD_IT_BE_THAT_BATTLE_READY_POSTURE                              = 14159,  -- Wait...could it be!? That battle-ready posture! That confident mien! No, no, you needn't tell me! You're an adventurer, come to help a troubled genius in his time of dire need! Am I right or am I right?
        AM_I_RIGHT_UH_YOU_RE_RIGHT_COULDN                                       = 14160,  -- Am I right? Uh...you're right. Couldn't be more wrong.
        AH_FOR_SHAME_TO_THINK_THE_WORLD_MUST                                    = 14161,  -- Ah, for shame! To think the world must wait until another day to bask in the brilliance of my unprecedented discovery!
        I_KNEW_IT_MY_WITS_ARE_AS_SHARP                                          = 14162,  -- I knew it! My wits are as sharp as ever, if I say so myself--which I just did!
        AS_YOU_SEE_THE_SUPREMELY_COMPLEX_EXPERIMENT_I                           = 14163,  -- As you see, the supremely complex experiment I'm conducting demands nothing short of my undivided attention, so I hope you'll forgive me if I speak to you from here.
        AT_ANY_RATE_HERE_IS_THE_TASK_I                                          = 14164,  -- At any rate, here is the task I would entrust to you. Certainly an adventurer of your caliber has heard of--perhaps even set foot in--the mountainous crags that lie beyond Gustaberg: the area they call Grauberg.
        IT_IS_THERE_SLEEPING_IN_THE_BED_OF                                      = 14165,  -- It is there, sleeping in the bed of a river that runs beneath a mountain vast, that one can find a very special variety of gold dust, imbued with just a speck, a smidgen, a sliver of magical energy! ...Or so they say.
        I_WOULD_ASK_YOU_TO_VENTURE_TO_GRAUBERG                                  = 14166,  -- I would ask you to venture to Grauberg and retrieve this vital ingredient for me, that the world--nay, the universe--might reap the harvest sown by the seeds of my immense genius! What say you, adventurer?
        WHAT_SAY_YOU_LEAVE_IT_TO_ME_I                                           = 14167,  -- What say you? Leave it to me! I say do your own work.
        WHAT_I_M_OFFERING_YOU_A_ONCE_IN                                         = 14168,  -- What!? I'm offering you a once-in-a-lifetime opportunity to share in a groundbreaking moment that will go down in the annals of science, and you would simply walk away!? I know not what vile madness takes you, man/woman], but may the Goddess have mercy on your soul!
        AH_EXCELLENT_EXCELLENT_I_KNEW_IT_FROM_THE                               = 14169,  -- Ah, excellent! Excellent! I knew it from the start--clearly, you're a man/woman] with a sense for history in the making!
        VERY_WELL_THEN_TAKE_THIS_AND_RETRIEVE_THE                               = 14170,  -- Very well, then. Take this % and retrieve the magical gold dust I seek.
        ACCORDING_TO_MY_THOROUGHLY_INFALLIBLE_CALCULATIONS_TWENTY_GRAINS        = 14171,  -- According to my thoroughly infallible calculations, twenty grains should do the trick.
        BRING_THEM_BACK_HERE_IN_THIS_AND_PREPARE                                = 14172,  -- Bring them back here in this %, and prepare to bear witness to the dawning of a new era in alchemy! You'll want to ready yourself a pair of shaded spectacles, 'cause the future is going to be bright, bright, bright!
        MY_ADVENTURING_FRIEND_HAVE_YOU_MANAGED_TO_SECURE                        = 14173,  -- My adventuring friend! Have you managed to secure the enchanted gold dust I seek? Why, we mustn't keep the world waiting any longer--a truly epoch-making moment hangs in the balance!
        HOW_TO_GET_TO_GRAUBERG_YOU_ASK_COME                                     = 14174,  -- How to get to Grauberg, you ask? Come to think of it, the path leading there has been obstructed for as long as I can remember. But hey, you're the adventurer--I'm sure you'll figure something out! Now, chop chop!
        WAIT_COULD_IT_BE_THAT_SELF_SATISFIED_EXPRESSION                         = 14175,  -- Wait, could it be!? That self-satisfied expression! That sprightly gait! No, no, don't tell me, now! You've returned triumphant with the ingredient I seek! Am I right or am I right?
        SPECTACULAR_SO_PURE_AND_SIMPLY_OOZING_WITH_MAGICAL                      = 14176,  -- Spectacular! So pure, and simply oozing with magical energy! To think that such immaculate specimens remain in this day and age...
        TO_TELL_THE_TRUTH_I_HAD_MY_DOUBTS                                       = 14177,  -- To tell the truth, I had my doubts that a scruffy-looking straggler like you could pull it off, but you've far exceeded my (admittedly low) expectations!
        BUT_WHY_AM_I_STANDING_AROUND_CHIT_CHATTING                              = 14178,  -- But why am I standing around chit-chatting with the help when there's history to be made!? Behold as I unveil the first step of the process that will redefine our glorious discipline!
        BWAHAHAHA_YES_YES_ALL_IS_PROCEEDING_PRECISELY_ACCORDING                 = 14179,  -- Bwahahaha! Yes...yes! All is proceeding precisely according to plan!
        NOW_ALL_I_DO_IS_TAKE_THE_REFINED                                        = 14180,  -- Now all I do is take the refined gold dust--like so--and a shiny new weapon specially prepared by our guild for this momentous occasion, and...
        HISTORY_HERE_I_COME_GENIUS_HAS_A_NEW                                    = 14181,  -- History, here I come! Genius has a new name, and that name is Titus!
        WHAT_NO_IT_COULDN_T_BE_FAILURE_I                                        = 14182,  -- What...? No! It couldn't be!? Failure!? I've failed!? Oh, unmerciful Goddess, how you torture me so!
        OH_ALAS_AND_ALACK_YEARS_OF_RESEARCH_FOR                                 = 14183,  -- Oh, alas and alack! Years of research for naught! Am I destined to live out the rest of my life as a nobody!? A grimy lump of fool's gold to be trodden beneath the feet of my more accomplished peers!? Woe, oh woe is me...!
        YOU_RE_STILL_HERE_PRAY_LEAVE_ME_I                                       = 14184,  -- You're still here? Pray leave me. I am a failure, a nothing, a nobody! I cannot bear to have anyone look upon my wretched self!
        HMM_WHAT_S_THAT_YOU_SAY_WHY_WHAT                                        = 14185,  -- Hmm? What's that you say? Why, what have we here!? Though the synthesis failed, the materials are miraculously intact...!?
        WHAT_LUCK_WHAT_FORTUNE_THE_GODDESS_SMILES_UPON                          = 14186,  -- What luck! What fortune! The Goddess smiles upon her poor Titus after all! Stand back, friend! I've been given another chance at history, and I mean to make the most of it!
        EUREKA_I_VE_DONE_IT_I_VE_TRULY                                          = 14187,  -- Eureka! I've done it! I've truly done it!
        I_REALLY_AM_A_GENIUS_WHY_I_NEVER                                        = 14188,  -- I really am a genius! Why, I never doubted myself for a second! See how it glows with unearthly power! Truly an achievement that will be celebrated by alchemists--nay, by enlightened beings the world over--for ages to come!
        WHAT_DOES_IT_DO_YOU_SAY_WHY_IT                                          = 14189,  -- What does it do, you say? Why, it imbues a potent dose of alchemical skill to anyone who wears it! Amazing, is it not?
        THINK_OF_IT_AS_MY_WAY_OF_SHARING                                        = 14190,  -- Think of it as my way of sharing just a smidge--a trifle, mind you--of my limitless genius to the less intellectually endowed! Ha-ha!
        AND_FOR_YOUR_CONTRIBUTIONS_TO_THIS_GLORIOUS_DAY                         = 14191,  -- And for your contributions to this glorious day, you may consider it yours! A round of applause for the good man/woman]!
        IT_S_JUST_A_PROTOTYPE_MIND_YOU_AND                                      = 14192,  -- It's just a prototype, mind you, and there are still a few kinks to be worked out, but hey, let's not sweat the details!
        THAT_GLOWING_SMILE_THAT_AWESTRUCK_EXPRESSION_DON_T                      = 14193,  -- That glowing smile! That awestruck expression! Don't tell me--you're simply overjoyed to own a piece of history. Am I right or am I right?
        ANYHOW_IT_S_BACK_TO_WORK_FOR_ME                                         = 14194,  -- Anyhow, it's back to work for me. This is one genius who isn't going to rest on his laurels! And don't be leaving town, okay? After all, it shall only be a matter of time before my next groundbreaking discovery!
        WHAT_YOU_SAY_YOU_VE_GOT_MY_CHOCOBO                                      = 14195,  -- What? You say you've got my chocobo!?
        THAT_S_GREAT_NEWS_THE_ONLY_TIME_I                                       = 14196,  -- That's great news! The only time I ever really feel relaxed is when I'm with that little guy.
        YOU_RE_RAISING_A_CHOCOBO_YOURSELF_AREN_T                                = 14197,  -- You're raising a chocobo yourself, aren't you? Let me teach you a story I always tell mine...
        YOU_VE_FOUND_MY_CHOCOBO                                                 = 14198,  -- You've found my chocobo!?
        YOU_JUST_MADE_MY_DAY_MISTER_LADY_THERE                                  = 14199,  -- You just made my day, mister/lady]! There hasn't been a day gone by that I haven't thought about the little squirt. As thanks for helping me out, let me teach you a story I know...
        THE_ONLY_THINGS_AN_ADVENTURER_NEEDS_ARE_COURAGE_2                       = 14200,  -- The only things an adventurer needs are courage, a good suit of armor...and companionship.
        YOU_VE_GOT_MY_CHOCOBO                                                   = 14201,  -- You've got my chocobo!?
        OH_THOSE_BIG_PUPPY_DOG_EYES_THAT_SWEET                                  = 14202,  -- Oh, those big, puppy-dog eyes! That sweet little chirp! I can't wait to see the little featherball again!
        AHEM_I_MUST_THANK_YOU_LET_ME_TEACH                                      = 14203,  -- Ahem... I must thank you. Let me teach you a story I often tell my chocobo...
        YOU_VE_FOUND_MY_CHOCOBO_HAVE_YOU                                        = 14204,  -- You've found my chocobo, have you?
        I_THOUGHT_HE_D_RUN_AWAY_BECAUSE_I                                       = 14205,  -- I thought he'd run away because I spend too long working.
        THANKS_FOR_FINDING_HIM_IN_RETURN_LET_ME                                 = 14206,  -- Thanks for finding him. In return, let me teach you a story I often tell my chocobo...
        GOODNESS_YOU_VE_FOUND_MY_CHOCOBO                                        = 14207,  -- Goodness, you've found my chocobo?
        TO_THINK_I_LL_GET_TO_SEE_THE                                            = 14208,  -- To think I'll get to see the little darling again...she was a real hit with the customers. I was afraid it wouldn't last...
        YOU_RE_RAISING_A_CHOCOBO_TOO_RIGHT_HERE                                 = 14209,  -- You're raising a chocobo too, right? Here, let me teach you a nice story...
        YOU_VE_GOT_MY_CHOCOBO_ARE_YOU_SERIOUS                                   = 14210,  -- You've got my chocobo!? Are you serious?
        IT_ALL_HAPPENED_IN_WEST_RONFAURE_JUST_WHEN                              = 14211,  -- It all happened in West Ronfaure... Just when I was thinking how beautiful the day was, thick fog seemed to appear out of nowhere and hid the little chocobo from my sight!
        THANK_YOU_SO_MUCH_FOR_FINDING_HIM_AS                                    = 14212,  -- Thank you so much for finding him! As thanks, let me teach you a story I often tell my chocobo...
        YOU_VE_YOU_VE_GOT_MY_CHOCOBO                                            = 14213,  -- You've...you've got my chocobo?
        WHAT_A_RELIEF                                                           = 14214,  -- ... What a relief...
        I_THANK_YOU_FOR_YOUR_KINDNESS_SIR_MA                                    = 14215,  -- I thank you for your kindness, sir/ma'am]. As thanks, let me teach you a story I often tell my chocobo...
        EH_YA_SAY_YA_VE_GOT_MY_CHOCOBO                                          = 14216,  -- Eh? Ya say ya've got my chocobo? Is that so?
        I_M_NOT_SURE_I_HEARD_THAT_RIGHT                                         = 14217,  -- I'm not sure I heard that right. Could ya speak up, or am I imagining things again?
        OHHH_BLESS_YOUR_SOUL_A_YOUNG_LAD_LASS                                   = 14218,  -- Ohhh, bless your soul. A young lad/lass] like you might just be able to use this... Let me tell you a little story, sonny/missy]...
        STOP_JOKING_AROUND_I_VE_GOT_WORK_TO                                     = 14219,  -- Stop joking around. I've got work to do. My chocobo's at home waiting for me to finish.
        YOU_SAY_YOU_VE_GOT_MY_CHOCOBO                                           = 14220,  -- You say you've got my chocobo?
        SIR_MA_AM_THE_ONLY_THINGS_AN_ADVENTURER                                 = 14221,  -- Sir/Ma'am], the only things an adventurer needs are courage, a good suit of armor, and lips that don't lie.
        YOU_SAY_YOU_VE_GOT_MY_CHOCOBO_2                                         = 14222,  -- You say you've got my chocobo?
        MY_CHOCOBO_WOULD_NEVER_LEAVE_ME_NOBODY_S                                = 14223,  -- My chocobo would never leave me! Nobody's closer than me and my chocobo!
        WELL_IT_S_TRUE_THAT_I_CAN_T                                             = 14224,  -- Well, it's true that I can't care for my chocobo as much as I'd like, considering my employment...but I'd never let it wander around lost. You must have me confused for someone else.
        GOODNESS_YOU_SAY_YOU_VE_GOT_MY_CHOCOBO                                  = 14225,  -- Goodness, you say you've got my chocobo?
        SORRY_BUT_IT_CAN_T_BE_MINE_MY                                           = 14226,  -- Sorry, but it can't be mine. My chocobo was entertaining customers just a moment ago.
        YOU_SAY_YOU_VE_GOT_MY_CHOCOBO_3                                         = 14227,  -- You say you've got my chocobo?
        THAT_CAN_T_BE_TRUE_I_WOULD_NEVER                                        = 14228,  -- That can't be true. I would never take my eyes off my chocobo while we're on a walk.
        THERE_ARE_TWO_KINDS_OF_CHOCOBOS_IN_THIS                                 = 14229,  -- There are two kinds of chocobos in this world: those that belong to me, and those that don't. The chocobo that you speak of is one of the latter.
        EH_YA_SAY_YA_VE_GOT_MY_CHOCOBO_2                                        = 14230,  -- Eh? Ya say ya've got my chocobo?
        GREETINGS_I_AM_A_JOURNEYMAN_TRAINER_FROM_THE                            = 14231,  -- Greetings. I am a journeyman trainer from the VCS, and I have been sent to this town to promote knowledge exchange between chocobo owners.
        WE_BELIEVE_THAT_THE_BEST_WAY_TO_PROMOTE                                 = 14232,  -- We believe that the best way to promote interaction between owners is through interaction between chocobos.
        AND_AFTER_COUNTLESS_VCS_CONFERENCES_WE_RECENTLY_AGREED                  = 14233,  -- And after countless VCS conferences, we recently agreed on the establishment of a new program--
        KAMP_KWEH                                                               = 14234,  -- Kamp Kweh!
        BREEDERS_NEED_ONLY_POSSESS_A_CHOCOBO_TO_JOIN                            = 14235,  -- Breeders need only possess a chocobo to join. Please speak with me again if you are interested.
        I_CAN_ANSWER_YOUR_QUESTIONS_REGARDING_KAMP_KWEH                         = 14236,  -- I can answer your questions regarding Kamp Kweh?
        WHAT_WOULD_YOU_LIKE_TO_KNOW_WHAT_EXACTLY                                = 14237,  -- What would you like to know? What exactly is Kamp Kweh? How do I sign up? Are there any restrictions? Nothing at all.
        KAMP_KWEH_IS_A_PLACE_WHERE_FELLOW_BREEDERS                              = 14238,  -- Kamp Kweh is a place where fellow breeders can bring their chocobos to interact with each other.
        AT_THE_CAMP_OWNERS_CAN_CHECK_THE_STATUS                                 = 14239,  -- At the camp, owners can check the status of their companions' animals...
        AS_WELL_AS_CONFIRM_BREEDING_COMPATIBILITY                               = 14240,  -- ...as well as confirm breeding compatibility.
        HOWEVER_PLEASE_NOTE_THAT_ANY_RESULTS_FROM_THESE                         = 14241,  -- However, please note that any results from these tests are merely estimates, and may not fully reflect the actual condition of an animal.
        OUR_WISH_IS_THAT_THROUGH_THE_VARIOUS_CAMP                               = 14242,  -- Our wish is that through the various camp activities we offer, your chocobo will have the opportunity to improve its skills.
        ONLY_ADVENTURERS_WHO_ARE_CURRENTLY_RAISING_A_CHOCOBO                    = 14243,  -- Only adventurers who are currently raising a chocobo can participate.
        OWNERS_CAN_ENROLL_THEIR_ANIMALS_ONCE_THEY_HAVE                          = 14244,  -- Owners can enroll their animals once they have hatched.
        TO_BEGIN_ADVENTURERS_SHOULD_FIRST_FORM_A_PARTY                          = 14245,  -- To begin, adventurers should first form a party of those who wish to participate, and then come talk to me or any of the other VCS journeyman trainers stationed throughout Vana'diel.
        PLEASE_NOTE_THAT_ONLY_UP_TO_SIX_CHOCOBOS                                = 14246,  -- Please note that only up to six chocobos can attend the camp at one time, so do not come as an alliance.
        WE_REFUSE_ADMISSION_TO_THE_FOLLOWING                                    = 14247,  -- We refuse admission to the following:
        ID_1_ANY_OWNERS_WHO_HAVE_NOT_CHECKED_UP                                 = 14248,  -- 1. Any owners who have not checked up on their chocobos recently. Those who feel that they may have been neglecting their animal may want to visit the stables before attempting to participate.
        ID_2_CHOCOBOS_WHO_ARE_SLEEPING_OR_HAVE_RUN                              = 14249,  -- 2. Chocobos who are sleeping or have run away.
        ID_3_CHOCOBOS_WHO_HAVE_YET_TO_BE_NAMED                                  = 14250,  -- 3. Chocobos who have yet to be named.
        ID_4_PARTY_MEMBERS_WHO_ARE_TOO_FAR_AWAY                                 = 14251,  -- 4. Party members who are too far away from the stables.
        WE_WOULD_NOT_THINK_OF_LEADING_A_CHOCOBO                                 = 14252,  -- We would not think of leading a chocobo away from its pen when the owner was not present.
        WELCOME_BACK_HAVE_YOU_COME_TO_ENROLL_IN                                 = 14253,  -- Welcome back. Have you come to enroll in Kamp Kweh?
        ENROLL_YES_NO                                                           = 14254,  -- Enroll? Yes. No.
        I_SEE_IF_YOU_WISH_TO_PARTICIPATE_IN                                     = 14255,  -- I see. If you wish to participate in the future, feel free to contact me or one of my companions.
        I_AM_SORRY_SIR_MA_AM_YOUR_CHOCOBO                                       = 14256,  -- I am sorry, sir/ma'am], your chocobo is currently unable to participate. Please confirm your chocobo's condition and speak with me again when everything is in order.
        NONE_OF_THE_OTHER_MEMBERS_OF_YOUR_PARTY                                 = 14257,  -- None of the other members of your party possess chocobos able to participate in camp activities. Please confirm their conditions and speak with me again when everything is in order.
