        IS_THE_TASTY_WEED_THAT_YOU_LL_NEED                                      = 14430,  -- % is the tasty weed that you'll need to start the game.
        TAKE_A_CLUMP_TO_THE_AREA_SPECIFIED_ON                                   = 14431,  -- Take a clump to the area specified on a chocograph and set it out in front of you. Before you know it, your very own chocobo will come running (or walking, depending on how many carrots you've been giving it) to your side.
