        ACCORDING_TO_MY_RECORDS_YOU_AND_YOUR_CHOCOBO                            = 14477,  -- According to my records, you and your chocobo have been quite successful in locating prairie treasure.
        ACCORDING_TO_MY_RECORDS_YOU_AND_YOUR_CHOCOBO_2                          = 14478,  -- According to my records, you and your chocobo have been quite successful in locating treasure out in the bush.
