        WITH_IT_YOU_WILL_BE_ALLOWED_TO_PARTICIPATE                              = 14481,  -- With it, you will be allowed to participate in Hot and Cold festivities in the Valkurm Dunes.
        WITH_IT_YOU_WILL_BE_ALLOWED_TO_PARTICIPATE_2                            = 14482,  -- With it, you will be allowed to participate in Hot and Cold festivities on the Buburimu Peninsula.
