        YOU_BEAR_THE_MARK_OF_A_TRUE_DIGGER                                      = 14486,  -- You bear the mark of a true digger, %!
        WHICH_IS_WHY_I_M_PROUD_TO_PRESENT                                       = 14487,  -- Which is why I'm proud to present you with this new chocograph for the rainforests of Yuhtunga and Yhoator.
        I_MUST_WARN_YOU_ALL_THE_DIFFERENT_TYPES                                 = 14488,  -- I must warn you, all the different types of exotic foliage in the jungles can play tricks on your chocobo's sense of smell. You'll have to comb wider patches of the landscape than before if you wish to uncover the bounty.
        WHICH_IS_WHY_I_M_PROUD_TO_PRESENT_2                                     = 14489,  -- Which is why I'm proud to present you with this new chocograph for the Eastern and Western Altepa Deserts.
        I_MUST_WARN_YOU_THE_UNRELENTING_HEAT_OF                                 = 14490,  -- I must warn you, the unrelenting heat of the noonday sun, combined with the deserts' loose sands, will take their toll on your chocobo. You must be extra careful in choosing where to dig, as your bird will tire quickly.
        VISIT_THE_CHOCOBO_CIRCUIT_OFF_TO_THE_RACES                              = 14491,  -- Visit the Chocobo Circuit? Off to the races! Not right now.
        THE_DOOR_IS_LOCKED                                                      = 14492,  -- The door is locked...
        WELCOME_KUPO                                                            = 14493,  -- Welcome, kupo!
        WELCOME_TO_THE_CHOCOBO_RACING_ASSOCIATION_S_CRA                         = 14494,  -- Welcome to the Chocobo Racing Association's (CRA) [San d'Oria/Bastok/Windurst] branch. This service desk is here to accommodate our beginning and intermediate racers.
        I_AM_SORRY_BUT_THERE_ARE_NO_RACES                                       = 14495,  -- I am sorry, but there are no races scheduled at the moment.
