        THE_ENDLESS_NIGHTMARE_WOULD_BE_ENDLESS_NO_LONGER                        = 16332,  -- The endless nightmare would be endless no longer.
        HAVE_YOU_EVER_PAUSED_TO_CONSIDER_EXACTLY_WHOSE                          = 16333,  -- Have you ever paused to consider exactly whose nightmare it is?
