        AND_YET_OUR_VERY_PRESENCE_HERE_IS_AN                                    = 16338,  -- And yet our very presence here is an affront to her. We are the source of her nightmare.
        THERE_IS_ONE_SECRET_TO_HUMANITY_S_SUCCESS                               = 16339,  -- There is one secret to humanity's success: ambition. Imagining a better future, it strives ever onward in search of it.
        HAVING_SEEN_THE_PROMISED_LAND_IT_RAGES_AND                              = 16340,  -- Having seen the promised land, it rages and struggles each day to become more than it was meant to be.
        AND_IT_CONTINUES_TO_CLAW_ITS_WAY_FORWARD                                = 16341,  -- And it continues to claw its way forward, even if what it aspires to be does not truly exist.
        ITS_INSATIABLE_AVARICE_DEFINES_IT_MORE_THAN_EVEN                        = 16342,  -- Its insatiable avarice defines it more than even it can possibly realize.
        BUT_I_AM_NOT_A_HUMAN_SUCH_AS                                            = 16343,  -- But I am not a human such as you. I will be--I must be--an existence far beyond the most grandiose thought of such petty, grasping beings.
        FOR_THAT_IS_WHAT_LIFE_IS_AND_THOSE                                      = 16344,  -- For that is what life is. And those who cannot reach that pinnacle are fated to perish.
        TIME_IS_A_CRUEL_BEAST_WHOSE_SAVAGENESS_CANNOT                           = 16345,  -- Time is a cruel beast whose savageness cannot be sated.
        EVERY_MAN_WOMAN_AND_CHILD_FEELS_ITS_CLAWS                               = 16346,  -- Every man, woman, and child feels its claws sinking into their backs, the talons digging ever deeper with each passing day.
