        ALL_I_WANTED_TO_DO_WAS_PROTECT_MY                                       = 16349,  -- All I wanted to do was protect my countrymen...my homeland...
        AN_ALTERNATE_WORLD_WITH_ALTERNATE_FATES_AND_ALTERNATE                   = 16350,  -- An alternate world, with alternate fates and alternate existences.
        I_GAMBLED_MY_OWN_LIFE_AWAY_TO_PROTECT                                   = 16351,  -- I gambled my own life away to protect the world I called home.
        CAN_YOU_TRULY_SAY_THAT_YOU_ANY_DIFFERENT                                = 16352,  -- Can you truly say that you [did/would have done] any different?
        I_CHANNELED_MY_LOVE_FOR_MY_HOMELAND_INTO                                = 16353,  -- I channeled my love for my homeland into power.
        WHEN_I_FELL_BEFORE_YOU                                                  = 16354,  -- When I fell before you...
        DID_IT_MEAN_EVERYTHING_WAS_FOR_NAUGHT                                   = 16355,  -- ...did it mean everything was for naught?
        I_AND_I_ALONE_HAVE_SEEN_THE_TRUE                                        = 16356,  -- I, and I alone, have seen the true nature of things in this world.
        AND_THUS_I_HAVE_LEARNED_WHY_ALL_BEINGS                                  = 16357,  -- And thus, I have learned why all beings that rise must fall.
