        DON_T_LET_IGNORANCE_CLOUD_YOUR_JUDGMENT                                 = 16361,  -- Don't let ignorance cloud your judgment!
        ID_16362                                                                = 16362,  -- %...
        WHAT_YOU_SEE_BEFORE_YOU_IS_IT_A                                         = 16363,  -- What you see before you--is it a dream, or something else?
        IS_THIS_A_DREAM_WHAT_ELSE_COULD_IT                                      = 16364,  -- Is this a dream? What else could it be? No. It's something more...
