        A_KEEN_EYE_AS_ALWAYS                                                    = 16366,  -- A keen eye, as always.
        THE_MINDS_OF_ALL_WHO_HAVE_EXISTED_AND                                   = 16367,  -- The minds of all who have existed--and all who will exist--are as one.
        AS_TOO_ARE_THE_LIGHT_AND_DARKNESS_INHERENT                              = 16368,  -- As, too, are the light and darkness inherent in the mothercrystals.
