        I_HAVE_SOUGHT_THEM_OUT_OF_MY_OWN                                        = 16372,  -- I have sought them out of my own volition, hoping to manipulate their essences for my own ends.
        DARK_INFERNAL_FORCES_SERVING_AS_A_COUNTERBALANCE_TO                     = 16373,  -- Dark, infernal forces, serving as a counterbalance to the light you hope to make manifest.
