        YOU_HAVE_SET_HISTORY_ON_ITS_PROPER_COURSE                               = 16399,  -- You have set history on its proper course yet again, having passed through the fourth gate that stood before you.
        YET_SELH_TEUS_S_WORDS_RING_TRUE_THE                                     = 16400,  -- Yet Selh'teus's words ring true--the darkness slumbering within you is great.
