        I_MUST_CONFESS_MY_TREPIDATION_AT_THE_CURRENT                            = 16402,  -- I must confess my trepidation at the current state of affairs. What if the darkness overcomes you not in the future, but even earlier than I had anticipated?
        WHAT_A_MORBID_STATE_OF_AFFAIRS_WE_FIND                                  = 16403,  -- What a morbid state of affairs we find ourselves in.
        WE_MUST_TAKE_SOLACE_IN_THE_HOPE_THAT                                    = 16404,  -- We must take solace in the hope that the orb will guide you to safety, so that you will be prepared for the Reckoning.
