        HELLO_EVERYONE_MY_NAME_S_NICE_TO_MEET                                   = 17026,  -- Hello, everyone. My name's %. Nice to meet you!
        OF_COURSE_INJECTING_YOUR_OWN_PERSONAL_FLAVOR_MAY                        = 17027,  -- Of course, injecting your own personal flavor may act as a conversation starter and help people to remember you.
        NO_MATTER_WHICH_ROUTE_YOU_CHOOSE_MAKE_SURE                              = 17028,  -- No matter which route you choose, make sure to always remain polite. There is no better way to start a friendship off on the right foot.
        WHEN_SPEAKING_WITH_OTHERS_IT_S_CRITICAL_TO                              = 17029,  -- When speaking with others, it's critical to listen and be mindful of what they say.
