        MANDRAGORA_MANIA_IS_A_GAME_IN_WHICH_YOU                                 = 17106,  -- Mandragora Mania is a game in which you battle for jingly by moving your mandragora pieces to the goal.
        YOUR_GOAL_IS_THE_ONE_ON_THE_RIGHT                                       = 17107,  -- Your goal is the [red/blue/green] one on the right, while your opponent's is the [blue/green/red] one on the left.
        AT_THE_START_OF_THE_GAME_THREE_MANDRAGORAS                              = 17108,  -- At the start of the game, three mandragoras each will be placed on the eight game areas, excluding the goal.
