        NOTE_THAT_THE_MANDRAGORAS_WILL_MOVE_FROM_THE                            = 17117,  -- Note that the mandragoras will move from the back first--last in, first out.
        YOU_WILL_RECEIVE_POINTS_KNOWN_AS_JINGLY_EACH                            = 17118,  -- You will receive points known as jingly each time one of your mandragoras reaches the goal.
        YOU_WILL_ENTER_YOUR_OPPONENT_S_TERRITORY_WHENEVER                       = 17119,  -- You will enter your opponent's territory whenever you go past the goal.
        IF_ONE_OF_YOUR_MANDRAGORAS_HAPPENS_TO_REACH                             = 17120,  -- If one of your mandragoras happens to reach the opponent's goal, the goal will be pushed back and your mandragora will return to your own area. You don't have to worry about your mandragora earning any jingly for your opponent.
